l_lang\";s:0:\"\";}}}}}i:26;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"Open Channels FM: The Evergreen Platform\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2552208\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"https://openchannels.fm/the-evergreen-platform/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:259:\"In this episode, Adam Weeks discusses a partnership between Servebolt and Crowd Favorite, focusing on innovative enterprise solutions. The partnership aims to address complex technological challenges, enabling businesses to prioritize growth over maintenance.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 08 Apr 2026 09:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:27;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"WordPress.org blog: How to Watch WordCamp Asia 2026 Live\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20368\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://wordpress.org/news/2026/04/watch-wc-asia-2026-live/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:5496:\"<p class=\"wp-block-paragraph\">WordCamp Asia 2026 will be available to watch live across three days of streaming, making it easy for the global WordPress community to follow along from anywhere. This year’s live streamed programming begins with a special Contributor Day broadcast, followed by two full conference days of presentations from across the WordPress community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This post gathers each official stream in one place so you can quickly find the right broadcast for each day. Bookmark this page and return throughout the event to watch live.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Day One: The Making of a WordPress Release</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Go behind the scenes of a WordPress release in this special Contributor Day live stream from WordCamp Asia 2026. Past release squad members come together to share stories, reflect on their experience, and talk about what it takes to bring a WordPress release to life. The Panel will go live at <strong>4:30 am UTC</strong>.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Day Two: Conference Livestreams</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Watch the second day of WordCamp Asia 2026 live for a full day of presentations and sessions. beginning at <strong>4:00 am UTC</strong>, including a Fireside chat with Mary Hubbard, which will begin at <strong>5:00 am UTC</strong> over on the Growth Stream.<br /></p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Foundation</h3>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Growth</h3>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Enterprise</h3>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Day Three: Conference Livestreams</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Watch the third day and final day of WordCamp Asia 2026 live, beginning at <strong>4:00 am UTC</strong> for another full day of presentations from across the community. Don’t forget to watch Ma.tt Mullenweg give the final keynote, which will begin on the Growth stream at <strong>10:00 am UTC</strong>.</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Foundation</h3>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Growth</h3>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Enterprise</h3>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">You can also explore the <a href=\"https://asia.wordcamp.org/2026/schedule/\"><strong>full schedule</strong></a> to see what is coming up across the event and plan your viewing. However you join, we hope you will follow along and be part of WordCamp Asia 2026.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-20372\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/20250220-DSC07465-scaled-2.webp?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /></figure>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 Apr 2026 13:57:21 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:28;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:81:\"Open Channels FM: Professionalizing Pricing Models for Open Source CMS Businesses\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2552157\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://openchannels.fm/professionalizing-pricing-models-for-open-source-cms-businesses/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:172:\"In this episode, Anne Bovelett chats with Dr. Christian Kurze discuss strategies for startups in open source CMS, emphasizing structured sales and sustainable monetization.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 Apr 2026 09:05:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:29;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:27:\"Gary: The Human in the Loop\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:25:\"https://pento.net/?p=5716\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"https://pento.net/2026/04/07/the-human-in-the-loop/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:6682:\"<p class=\"wp-block-paragraph\">If you&#8217;ve been paying attention to LLM-based coding tools in the past few months, you&#8217;ll have seen a seismic shift in how they&#8217;re being used. Even 12 months ago, they were little more than glorified auto-complete tools: useful for quickly repeating patterns, but terrible at producing well structured, thoughtful, maintainable code. More recently, however, there seems to have been a new equilibrium reached, where an experienced engineer can guide these tools to consistently produce high quality code. Small course adjustments seem to have an outsized effect, resulting in the &#8220;Human in the Loop&#8221; paradigm that&#8217;s become so popular.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Why It Works</h2>\n\n\n\n<p class=\"wp-block-paragraph\">&#8220;Code is Poetry&#8221; has been my approach to writing code for as long as I can remember. Software is a form of expression, and the way you create that expression is through code. So, to make beautiful software, you need to write beautiful code. But, what happens when you don&#8217;t need to write code to create the software?</p>\n\n\n\n<p class=\"wp-block-paragraph\">Suddenly, the code becomes entirely about outcomes. It needs to be correct, functional, and maintainable, but it doesn&#8217;t need to be seen as a form of expression itself. Instead, the creative decisions move further up the stack, to the architectural level. You can write beautiful software by writing thoughtful specifications, instead.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That&#8217;s not to say that technical abilities are suddenly obsolete. You still need to know what&#8217;s possible and realistic to be able to tell the LLM what to build, and to redirect it when it goes in a different direction. You need to be able to read and comprehend the code, you just don&#8217;t need to memorise every function signature.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The Temptation</h2>\n\n\n\n<p class=\"wp-block-paragraph\">So, if an LLM can write code for me, what else can it do? Marketing copy? Emails? Opinion blog posts? I could ask Claude to write 10 paragraphs on the &#8220;The Human in the Loop&#8221;, but would you have even read this far if you thought this post was LLM generated? Of course not! I can promise you that every word of this post (and every other post on my blog) was written by me.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Respect for the Reader</h2>\n\n\n\n<p class=\"wp-block-paragraph\">If I want you to read this post, and seriously consider the arguments I&#8217;m making, the least I can do is write it myself. It goes beyond that, however. LLMs can write functional code, but they can&#8217;t write beautiful software. When the text <em>is</em> the creative act, there&#8217;s no way for the LLM to write the text without compromising your creativity. If you&#8217;re the Human in the Loop for a blog post, you&#8217;re not injecting your voice, your perspective, or your personality into the post: you&#8217;re rubber stamping whatever feels good enough, and that&#8217;s a very low bar to clear.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">&#8220;Good enough&#8221; isn&#8217;t actually good enough. </p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">A measure of the complexity of a written piece of text is called &#8220;perplexity&#8221;. It measures the randomness of how the text flows, and it&#8217;s probably the thing you&#8217;re noticing when you know you&#8217;re reading LLM-generated text, but you can&#8217;t quite articulate why. It&#8217;s an uncanny valley thing: it looks like writing, it reads like writing, it might even flow like writing, but the vibes are off.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The good news is, you&#8217;re not going insane, recent research shows that <a href=\"https://www.researchgate.net/publication/395972099_How_Well_Do_LLMs_Imitate_Human_Writing_Style\">there is a measurable difference between human written text, and LLM generated text</a>. LLM generated text is inherently less random, which makes sense when you remember that LLMs are, at their core, giant statistical models that are really good at figuring out &#8220;what&#8217;s the most likely bit of text to come next&#8221;.</p>\n\n\n\n<figure class=\"wp-block-image size-large has-custom-css wp-custom-css-20396e00\"><img alt=\"\" class=\"wp-image-5720\" height=\"1024\" src=\"https://pento.net/wp-content/uploads/2026/04/Screenshot-2026-04-07-at-3.01.26-pm-333x1024.png\" width=\"333\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">The LLM as the Assistant</h2>\n\n\n\n<p class=\"wp-block-paragraph\">That&#8217;s not to say that LLMs are completely useless when it comes to writing, but we need to use them the right way. While they shouldn&#8217;t be generating text, they can absolutely be used to help you write. Over the last month or so, I&#8217;ve been working on <a href=\"https://pento.net/2026/03/28/claudaborative-editing-0-2-now-with-500-more-collaboration/\">Claudaborative Editing</a>, an experiment to see exactly how much they can help with the writing process. I&#8217;ve been building it directly into the WordPress editor, allowing me to plan, write, review, and publish this post from the one place. An LLM assisted, but <em>every word of it was written by me alone</em>. My goal isn&#8217;t to replace the author, or to make it easier to fill the web with LLM-generated dreck, it&#8217;s to help me (and hopefully you, too!) improve your writing, while still keeping it fundamentally yours.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Where Does Creativity Live?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">When you&#8217;re evaluating these tools, &#8220;can an LLM do this?&#8221; isn&#8217;t the question you need to ask. Instead, think about where the creative part of the process lives. For software, that&#8217;s in the design decisions and the architecture, the final product is the expression of that creativity. The specifics of the implementation don&#8217;t really matter. For a blog post, or any writing for that matter, the creativity lives in the act of writing. To delegate that to an LLM is to delegate your own creativity.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Here&#8217;s what I believe: the best uses of LLM tools are when they augment humans, rather than try to replace them. They enhance the inherent creativity of their human operator, they don&#8217;t suppress it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This belief guides how I use LLMs, and how I build tools that help others use LLMs, too. I&#8217;ll be pushing out a new release of Claudaborative Editing in the next few days, I hope you&#8217;ll give it a go!</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 Apr 2026 06:38:33 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Gary\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:30;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Matt: TheOpenSource\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151870\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:36:\"https://ma.tt/2026/04/theopensource/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:603:\"<p class=\"wp-block-paragraph\">It&#8217;s very cool to see <a href=\"https://t3.gg/\">Theo / t3.gg</a>&#8216;s open source arc.</p>\n\n\n\n<figure class=\"wp-block-embed alignwide is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Just in general, with people creating more software than ever, it&#8217;s so exciting to see an explosion of open source and a growing understanding of why working together on open source makes so much sense for the future we want to build.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 Apr 2026 00:01:28 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:31;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"Open Channels FM: Finding Balance: The Importance of Downtime at Conferences\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551269\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:82:\"https://openchannels.fm/finding-balance-the-importance-of-downtime-at-conferences/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:171:\"Conferences are hectic, but experts say taking breaks is key for success. Pausing helps recharge, absorb info, and connect meaningfully with others. Balance is everything!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 06 Apr 2026 08:27:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:32;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"Matt: Easter Thoughts\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151842\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"https://ma.tt/2026/04/easter-thoughts/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3604:\"<p class=\"wp-block-paragraph\">You call yourself a Christian engineer, but you haven’t given your life to Open Source? Huh.</p>\n\n\n\n<p class=\"wp-block-paragraph\">What license would Jesus choose? I don’t know if it’s GPL or MIT, but sure as heck it isn’t proprietary.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Letting proprietary code dictate your life is like following a Bible you’re not allowed to read. Beware those who would seek to mediate your relationship to the divine.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Happy Easter, y’all. <img alt=\"🙏\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f64f.png\" style=\"height: 1em;\" /><img alt=\"🐰\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f430.png\" style=\"height: 1em;\" /><img alt=\"🌈\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f308.png\" style=\"height: 1em;\" /> </p>\n\n\n\n<p class=\"wp-block-paragraph\">Update: BTW, the above would probably be a lot better if I spoke it, because people would hear <em>a very humorous tone, but that&#8217;s not clear from the text! So some have said I come off pretty jerky,</em> and some said blasphemous. Fair! I&#8217;m also not saying it&#8217;s literally funny, it just would be a little clearer I was trying. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Also, I mean examples as possible metaphors or parallels and not literally, but never say that up front. Also as thought experiment, not literally as judgey. &#8220;No&#8221; or &#8220;it is totally fine&#8221; are valid answers to the first question, lots of more possibilities — the &#8220;Huh&#8221; is meant more out of curiosity than judgment, a conversation starter, not an ender.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Finally the ender <strong>&#8220;Happy Easter, y&#8217;all)&#8221;</strong> <em>in my Houston culture and context</em> / the South  would be pretty clear as actually happy, friendly and playful. But said in a different tone or without that context, the opposite!  I have friends in NYC for whom that would read deep sarcasm, a big FU and rude bye. I didn&#8217;t think of that!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Anyway, I&#8217;ve learned a lot from the feedback, will probably still learn more, and want to deeply appreciate the people who care enough to give it to me and spend time explaining and answering my questions. Thanks, y&#8217;all! (Not sarcastic <img alt=\"🙂\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f642.png\" style=\"height: 1em;\" /> <img alt=\"🙂\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f642.png\" style=\"height: 1em;\" /> <img alt=\"🙂\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f642.png\" style=\"height: 1em;\" /> &lt;&#8212; Real smiles and gratitude, not smug.) </p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;m not thanking all the Twitter / X trolls, though, and I&#8217;m not going to engage any more because the real or perceived trolling makes it almost impossible to change, nor do I harbor any illusions of changing some minds. I&#8217;ve devoted hundreds of hours to it in the past, but it didn&#8217;t help, and that took a lot of time away from my favorite people and loved ones.</p>\n\n\n\n<p class=\"wp-block-paragraph\">(Also, I think something has changed; in open source and WordPress, we&#8217;d fight like crazy, but ended up coming together or having a meal afterward before diving back in. Social media I think has made that rarer and harder.)</p>\n\n\n\n<p class=\"wp-block-paragraph\">(and the new Spring colors are on the site.)</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 05 Apr 2026 15:40:50 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:33;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"Matt: Turn Every Page\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151827\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"https://ma.tt/2026/04/turn-every-page/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:504:\"<p class=\"wp-block-paragraph\">If you&#8217;re looking for a good watch this weekend, I couldn&#8217;t recommend more the documentary <a href=\"https://www.google.com/search?q=turn+every+page\">Turn Every Page – The Adventures of Robert Caro and Robert Gottlieb</a>. The craft of research, writing, and editing is presented in the most beautiful way possible. Around 400,000 words were removed from <a href=\"https://amzn.to/4sdRYn6\">The Power Broker</a>, which was ultimately published as 1,162 pages.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 05 Apr 2026 01:14:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:34;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:22:\"Matt: Pedro Franceschi\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151811\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:39:\"https://ma.tt/2026/04/pedro-franceschi/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:428:\"<p class=\"wp-block-paragraph\">This <a href=\"https://www.ashleevance.com/\">Ashlee Vance</a> interview of Pedro Franceschi from Brex contains so many interesting stories it might cause you to reconsider what it means to be a CEO.</p>\n\n\n\n<figure class=\"wp-block-embed alignwide is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 03 Apr 2026 19:07:36 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:35;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"Open Channels FM: Self-hosted WordPress Optimized Runtime on Docker (SWORD)\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551797\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://openchannels.fm/self-hosted-wordpress-optimized-runtime-on-docker-sword/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:182:\"In the CloudFest Hackathon, Jan Willem shared his team\'s project, SWORD, a self-hosted control panel for WordPress, highlighting collaboration, technical challenges, and team spirit.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 03 Apr 2026 10:18:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:36;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:44:\"Open Channels FM: WEB Responsibility Scanner\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551824\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"https://openchannels.fm/web-responsibility-scanner/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:209:\"Ekaterina Streltsova introduced the BEP Responsibility Scanner at CloudFest Hackathon, addressing web sustainability, accessibility issues, and legal compliance, emphasizing the need for open-source solutions.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 03 Apr 2026 09:07:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:37;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"Open Channels FM: WP Plugin Insight\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551774\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:42:\"https://openchannels.fm/wp-plugin-insight/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:178:\"Javier Casares and Mark Heijnen discuss WP Plugin Insight, a project enhancing WordPress plugin discovery through AI-driven analysis of compatibility, security, and translations.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 03 Apr 2026 07:45:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:38;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"Matt: EmDash Feedback\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151783\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"https://ma.tt/2026/04/emdash-feedback/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:6962:\"<p class=\"wp-block-paragraph\">So, two other Matts at <a href=\"https://www.cloudflare.com/\">Cloudflare</a> announced <a href=\"https://blog.cloudflare.com/emdash-wordpress/\">EmDash — the spiritual successor to WordPress that solves plugin security</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">(Is it <a href=\"https://en.wikipedia.org/wiki/Nominative_determinism\">nominative determinism</a> or a simulation glitch that everyone trying to terraform the web has some variation of &#8220;Matthew&#8221; in their name? I was in a call set up by Matthew Prince, talking to Matt Taylor and Matt Kane, with my right hand there, <a href=\"https://matiasventura.com/\">Matías</a>.)</p>\n\n\n\n<p class=\"wp-block-paragraph\">First, I&#8217;m going to tell you why this isn&#8217;t spiritually tied to WordPress at all, then why they haven&#8217;t solved plugin security, and finally offer some suggestions.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The Spirit of WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress exists to democratize publishing. That means we put it <a href=\"https://ma.tt/2026/03/wordpress-everywhere/\">everywhere</a>. You can run WordPress on a Raspberry Pi, on your phone, on your desktop, on a random web host in Indonesia charging 99 cents a month, and you can run it scaled up on AWS or across multiple datacenters. </p>\n\n\n\n<p class=\"wp-block-paragraph\">The same code. When you download <a href=\"https://wordpress.org/playground/\">WordPress Playground</a> you&#8217;re running the same code that&#8217;s being attacked a thousand times a second at <a href=\"https://www.whitehouse.gov/\">WhiteHouse.gov</a>. That&#8217;s what we mean when we say <em>democratization</em>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">It&#8217;s all built on open source and web standards. You can run it anywhere; there&#8217;s no lock-in.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That&#8217;s why we do what we do. It&#8217;s really hard. You can come after our users, but please don&#8217;t claim to be our spiritual successor without understanding our spirit.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The Spirit of EmDash</h2>\n\n\n\n<p class=\"wp-block-paragraph\">I think EmDash was created to sell more Cloudflare services. And that&#8217;s okay! It can kinda run on Netlify or Vercel, but good stuff works best on Cloudflare. This is where I&#8217;m going to stop and say, I really like Cloudflare! I think they&#8217;re one of the top engineering organizations on the planet; they run incredible infrastructure, and their public stock is one of the few I own. And I love that this is open source! That&#8217;s more important than anything. I will never belittle a fellow open source CMS; I only hate the proprietary ones.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you want to adopt a CMS that will work seamlessly with Cloudflare and make it hard for you to ever switch vendors, EmDash is an incredible choice.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Claimed Plugin Security</h2>\n\n\n\n<p class=\"wp-block-paragraph\">In another example of them not understanding the spirit of WordPress, the fact that plugins can change every aspect of your WordPress experience is a feature, not a bug! And their sandboxing breaks down as soon as you look at what most WordPress plugins do. </p>\n\n\n\n<p class=\"wp-block-paragraph\">I know we get a bad rep because there are 62k plugins with wildly variable engineering quality, and more every day, and when one installed on 0.01% of our user base has a vulnerability, a bunch of websites write breathless articles that get clicks saying &#8220;122,000 WordPress Sites Vulnerable!&#8221;</p>\n\n\n\n<p class=\"wp-block-paragraph\">That, by the way, I think we&#8217;ll be able to fix in the next 18 months with AI. The plugin security <strong>only</strong> works on Cloudflare.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Critical Feedback</h2>\n\n\n\n<p class=\"wp-block-paragraph\">As I said, we had a call with Cloudflare on March 23rd, where they asked for feedback on this thing they built but didn&#8217;t tell us the name, said it would probably launch in their developer week towards the end of April, and some top colleagues and I offered to help. I wish I could say the things I&#8217;m saying in this blog post on that call, and if they had just shared the announcement post I could have, but in the spirit of open source here&#8217;s what I would have said:</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li>If they had said the name I would have asked if they had any other options because I have an <a href=\"https://emdash.codes/\">amazing colleague named Emdash</a> who is doing some of the most exciting stuff with WordPress and AI. (BTW I think our Em will have more impact on the web than this in five years.)</li>\n\n\n\n<li>I actually think the product is very solid, there&#8217;s some excellent engineering, migration tools, it&#8217;s very fast, and the Astro integration is nice.</li>\n\n\n\n<li>I&#8217;d be surprised if this doesn&#8217;t get tens of thousands of sites on it.</li>\n\n\n\n<li>The UI is in the <a href=\"https://en.wikipedia.org/wiki/Uncanny_valley\">uncanny valley</a> of being sorta-WordPress sorta-not. I know it wasn&#8217;t a weekend vibecode project, but it has some of that smell. Stuff breaks at the edges.</li>\n\n\n\n<li>I think using TinyMCE is a regression, and they should adopt <a href=\"https://github.com/wordpress/gutenberg\">Gutenberg</a>, which we licensed and created to be used by other CMSes. (Correction: They use <a href=\"https://www.portabletext.org/\">Portable Text</a> not TinyMCE, but same UI criticism applies.)</li>\n\n\n\n<li><a href=\"https://github.com/emdash-cms/emdash/tree/main/skills\">The Skills are amazing</a>, a brilliant strategy, and we need to do the same as soon as possible. I&#8217;ve been working on something similar and got some good ideas from their implementation.</li>\n\n\n\n<li>I&#8217;m not going to say which parts, but they copied a lot of things we&#8217;re planning to kill. Build from first principles. Make it better. Skate to where the puck is going.</li>\n</ol>\n\n\n\n<p class=\"wp-block-paragraph\">There&#8217;s a new CMS every other day. And that&#8217;s great! I love building CMSes and I totally get why other people do, too.</p>\n\n\n\n<h2 class=\"wp-block-heading\">In Conclusion</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Some day, there may be a spiritual successor to WordPress that is even more open. When that happens, I hope we learn from it and grow together. [removed &#8220;out of your mouth&#8221; sentence, too spicy for Western palates.] I&#8217;ve mostly focused on this post on just the software, but WordPress is also so much about the community — the meetups, the WordCamps, the art, the college programs, the tattoos, the books&#8230; The closest thing I&#8217;ve seen to a spiritual successor isn&#8217;t another CMS, it&#8217;s been <a href=\"https://openclaw.ai/\">OpenClaw</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Thanks to colleague <a href=\"https://bt.hn/\">Batuhan İçöz</a> for helping review this.</em></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 03 Apr 2026 01:32:27 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:39;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"WordPress.org blog: From AI to Open Source at WordCamp Asia 2026\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20341\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://wordpress.org/news/2026/04/wcasia-2026-sessions/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:10931:\"<p class=\"wp-block-paragraph\"><strong>April 9-11, 2026 | Jio World Convention Centre, Mumbai, India</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">WordCamp Asia 2026 brings the WordPress community to Mumbai, India, from April 9 to 11, with a schedule shaped around artificial intelligence, enterprise WordPress, developer workflows, product strategy, and open source collaboration. For attendees planning their time, the program offers a useful view of the ideas, tools, and practical challenges shaping WordPress today.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-82d461e8 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" href=\"https://asia.wordcamp.org/2026/event-pass/\" rel=\"noreferrer noopener\" target=\"_blank\">Get Your Event Pass</a></div>\n\n\n\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" href=\"https://asia.wordcamp.org/2026/schedule/\" rel=\"noreferrer noopener\" target=\"_blank\">WC Asia Schedule</a></div>\n\n\n\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" href=\"https://asia.wordcamp.org/2026/\" rel=\"noreferrer noopener\" target=\"_blank\">About WordCamp Asia</a></div>\n</div>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-19211\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/10/20250220-DSC_1853-scaled-1.jpg?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Keynotes to Set the Stage</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The keynote sessions at WordCamp Asia 2026 help frame some of the biggest conversations at this year’s event.</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-20366\" height=\"1076\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-02-at-11.31.10-am.png?resize=1078%2C1076&#038;ssl=1\" width=\"1078\" /><figcaption class=\"wp-element-caption\"><a href=\"https://asia.wordcamp.org/2026/speaker/matt-mullenweg/\">Ma.tt Mullenweg</a>, co-founder of WordPress and CEO of Automattic, is expected to speak about the future of the open web and the ever-evolving role that WordPress plays.</figcaption></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-20346\" height=\"986\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/03/Screenshot-2026-03-31-at-11.47.01-am.png?resize=984%2C986&#038;ssl=1\" width=\"984\" /><figcaption class=\"wp-element-caption\"><a href=\"https://asia.wordcamp.org/2026/speaker/mary-hubbard/\">Mary Hubbard</a>, Executive Director of WordPress, will also join a fireside chat moderated by <a href=\"https://asia.wordcamp.org/2026/speaker/shilpa-shah/\">Shilpa Shah</a>, focusing on leadership, education initiatives, artificial intelligence, and community growth.</figcaption></figure>\n</div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">Together, they offer an early view of the themes and discussions unfolding across WordPress in 2026.<br /></p>\n\n\n\n<h2 class=\"wp-block-heading\">AI, Automation, and the Future of WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Artificial intelligence is one of the clearest threads running through the program. Sessions from <a href=\"https://asia.wordcamp.org/2026/speaker/fellyph-cintra/\">Fellyph Cintra</a>, <a href=\"https://asia.wordcamp.org/2026/speaker/fumiki-takahashi/\">Fumiki Takahashi</a>, and <a href=\"https://asia.wordcamp.org/2026/speaker/nirav-mehta/\">Nirav Mehta</a> examine how AI is already influencing WordPress through Core discussions, testing workflows, plugin development, and day-to-day implementation. That same theme continues in sessions on marketing and content strategy, including <a href=\"https://asia.wordcamp.org/2026/speaker/adeline-dahal/\">Adeline Dahal’s</a> work on structuring WordPress content to make it more machine-readable. </p>\n\n\n\n<p class=\"wp-block-paragraph\">This cross-section of presentations shows how automation is moving from concept to practice. From autonomous testing with WordPress Playground to AI-supported development workflows, these sessions highlight applicable tools and skills that teams can start using right away, not just concepts. For attendees interested in where WordPress is heading, this is one of the strongest themes across the event.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Enterprise WordPress and Scalability</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Enterprise sessions take that discussion further by focusing on scale, architecture, and operational complexity. <a href=\"https://asia.wordcamp.org/2026/speaker/rahul-bansal/\">Rahul Bansal</a>, <a href=\"https://asia.wordcamp.org/2026/speaker/james-giroux/\">James Giroux</a>, Anirban Mukherji, and Abid Murshed are among the speakers exploring how WordPress supports larger organizations, more complex commerce systems, and demanding digital environments. Their sessions look at growth, implementation, and the kinds of decisions that matter when WordPress is supporting business-critical work.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Other talks in this track focus on the realities of enterprise operations, including migration risk, observability, and long-term performance. Together, they show how WordPress continues to adapt to larger systems and more complex digital ecosystems without losing the flexibility that makes it widely used in the first place.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Developer Experience and Modern Practices</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The developer track stays grounded in both Core tools and everyday engineering practice. <a href=\"https://asia.wordcamp.org/2026/speaker/ryan-welcher/\">Ryan Welcher</a> will cover the Interactivity API, <a href=\"https://asia.wordcamp.org/2026/speaker/jonathan-desrosiers/\">Jonathan Desrosiers</a> will look at automation in open source, and <a href=\"https://asia.wordcamp.org/2026/speaker/takayuki-miyoshi/\">Takayuki Miyoshi</a> will introduce a schema-sharing approach to form management. These sessions point to a broader shift toward building WordPress systems that are more dynamic, maintainable, and easier to scale over time.</p>\n\n\n\n<p class=\"wp-block-paragraph\">These more technical presentations also include sessions on the WordPress HTML API, Content Security Policy, open source data pipelines, and evolving plugin standards. Rather than focusing on a single type of builder, this part of the schedule addresses developers working across infrastructure, security, front-end experiences, and long-term platform health.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Community, Education, and Open Source</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The schedule also makes space for the people and ideas that support WordPress beyond engineering alone. A panel featuring <a href=\"https://asia.wordcamp.org/2026/speaker/anand-upadhyay/\">Anand Upadhyay</a> and <a href=\"https://asia.wordcamp.org/2026/speaker/maciej-pilarski/\">Maciej Pilarski</a>, moderated by <a href=\"https://asia.wordcamp.org/2026/speaker/destiny-kanno/\">Destiny Kanno</a>, looks at education initiatives and student pathways into open source. <a href=\"https://asia.wordcamp.org/2026/speaker/kazuko-kaneuchi/\">Kazuko Kaneuchi</a> will reflect on the story of Wapuu and the culture of contribution around WordPress. At the same time, <a href=\"https://asia.wordcamp.org/2026/speaker/kotaro-kitamura/\">Kotaro Kitamura</a> and <a href=\"https://asia.wordcamp.org/2026/speaker/chiharu-nagatomi/\">Chiharu Nagatomi</a> will share how WordPress and its community shaped their professional journeys.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That wider perspective continues in sessions on product thinking, marketing, career growth, and business strategy. <span style=\"margin: 0px; padding: 0px;\">Speakers, including <a href=\"https://asia.wordcamp.org/2026/speaker/nabin-jaiswal/\" rel=\"noreferrer noopener\" target=\"_blank\">Nabin Jaiswal</a>, <a href=\"https://asia.wordcamp.org/2026/speaker/himani-kankaria/\" rel=\"noreferrer noopener\" target=\"_blank\">Himani Kankaria</a>, <a href=\"https://asia.wordcamp.org/2026/speaker/julian-song/\" rel=\"noreferrer noopener\" target=\"_blank\">Julian Song</a>, <a href=\"https://asia.wordcamp.org/2026/speaker/karishma-sundaram/\" rel=\"noreferrer noopener\" target=\"_blank\">Karishma Sundaram</a>, <a href=\"https://asia.wordcamp.org/2026/speaker/sandeep-kelvadi/\" rel=\"noreferrer noopener\" target=\"_blank\">Sandeep Kelvadi</a>, <a href=\"https://asia.wordcamp.org/2026/speaker/aviral-mittal/\" rel=\"noreferrer noopener\" target=\"_blank\">Aviral Mittal</a>, <a href=\"https://asia.wordcamp.org/2026/speaker/anh-tran/\" rel=\"noreferrer noopener\" target=\"_blank\">Anh Tran</a>, and <a href=\"https://asia.wordcamp.org/2026/speaker/anna-hurko/\" rel=\"noreferrer noopener\" target=\"_blank\">Anna Hurko,</a> explore how WordPress works an</span>d connects with decision-making, discoverability, professional development, and organizational growth. Taken together, these sessions reflect one of WordPress’s long-standing strengths: its ability to connect software, learning, and community in the same space.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Hands-on Workshops</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Hands-on workshops round out the schedule, offering practical sessions for attendees who want to move from ideas to implementation. They include:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>From On-Demand to Cloud: Automate WordPress Installations Like a Pro</li>\n\n\n\n<li>AI + MCP to build, manage, and automate WordPress end-to-end</li>\n\n\n\n<li>Building AI Agents with self-editing memory</li>\n\n\n\n<li>Building Better WordPress Experiences with AI-Driven Development Workflows</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Explore the <strong><a href=\"https://asia.wordcamp.org/2026/schedule/\">full schedule</a></strong> to plan your sessions, and get your <strong><a href=\"https://asia.wordcamp.org/2026/event-pass/\">event pass</a></strong> to join WordCamp Asia 2026 in Mumbai.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-19213\" height=\"754\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/10/wordcamp-asia-2025-family-photo.webp?resize=1024%2C754&#038;ssl=1\" width=\"1024\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Mumbai is calling. See you at WordCamp Asia 2026! </p>\n\n\n\n<p class=\"wp-block-paragraph\"><em><strong>Note: </strong>Much of the credit belongs to <a href=\"https://profiles.wordpress.org/webtechpooja/\">@webtechpooja</a> (<a href=\"https://profiles.wordpress.org/webtechpooja/\">Pooja Derashri</a>) for help in writing this piece.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 02 Apr 2026 16:10:35 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:40;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"Open Channels FM: FAIR Package Management for TYPO3\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551748\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"https://openchannels.fm/fair-package-management-for-typo3/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:186:\"Key figures from the FAIR TYPO3 hackathon discuss the platform-agnostic FAIR protocol, its integration with TYPO3, and advancements in digital goods distribution across multiple systems.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 02 Apr 2026 10:49:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:41;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Matt: Taxonomist\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151765\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://ma.tt/2026/04/taxonomist/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:6072:\"<p class=\"wp-block-paragraph\">I&#8217;m really excited to introduce a project I worked on with various AI agents the other night, which I think represents a new way we might build things in the future.</p>\n\n\n\n<p class=\"wp-block-paragraph\">First, the problem: My WordPress site has 5,600+ posts going back decades, and I had some categories that were old and I didn&#8217;t really use anymore, and I wasn&#8217;t happy with the structure. Every time I made a new post, it irked me a little, and I had this long-standing itch to go back and clean up all my categories, but I knew it was going to be a slog.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Let me present<span style=\"margin: 0px; padding: 0px;\"> <a href=\"https://github.com/m/taxonomist\" target=\"_blank\">Taxonomist</a>, a new open-source tool you can run with one copy-and-paste</span> command line that solves this problem. Here&#8217;s the idea:</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li>You run this code in your terminal, and it spins up a Claude Code instance that asks you for your URL.</li>\n\n\n\n<li>Then it takes that and figures out what type of site you have, which APIs are available, and starts downloading all your posts locally for analysis.</li>\n\n\n\n<li>Sub-agents analyze every post against your current categories and thinks about suggesting new ones.</li>\n\n\n\n<li>It previews all the changes.</li>\n\n\n\n<li>Tries a variety of ways to authenticate against your site and make all the changes.</li>\n\n\n\n<li>Logs everything locally, so anything is reversible later.</li>\n</ol>\n\n\n\n<p class=\"wp-block-paragraph\">THIS IS VERY ALPHA. PROBABLY BUGGY. BE CAREFUL WITH IT. PATCHES WELCOME. MAYBE MAKE A BACKUP OF YOUR SITE BEFORE YOU CHANGE IT.</p>\n\n\n\n<p class=\"wp-block-paragraph\">It kind of just worked. I ran it live against ma.tt and it cleaned up a ton of stuff pretty much exactly how I wanted. But there&#8217;s a lot of weird stuff happening here, so I don&#8217;t know quite what this is yet.</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li>It&#8217;s very non-deterministic! There is some pre-written code, and probably could be more, but a lot of the code is generated on the fly by your agent. This creates interesting bugs where people testing with less powerful models had some odd behavior.</li>\n\n\n\n<li>I kind of want a directory of these useful AI agents on WordPress.org, but also, there&#8217;s something a little strange about trusting a remote shell script to run on your machine.</li>\n\n\n\n<li>I tested this with Claude, but there&#8217;s no reason Codex couldn&#8217;t use the repo in the exact same way, and I&#8217;d love to improve the quick start script to start by detecting all the agents you have, asking which you&#8217;d like to use, and also which directory you&#8217;d like to work in. I think we could kill the <code>cd taxonomist-main &amp;&amp; claude \"start\"</code> part of it.</li>\n\n\n\n<li>Because much of the code and commands are generated on the fly from prompts, it&#8217;s very resilient! I&#8217;ve seen people try it, and it ran into errors with libraries or whatever, but it just figured out how to work around them.</li>\n\n\n\n<li>I&#8217;d love it if, at the end of every session, there was a moment for self-reflection where the agent would take the repository and suggest upstream issues and PRs based on anything that went wrong. Then this could recursively self-improve very quickly.</li>\n\n\n\n<li>There are some obvious improvements to this, for example, doing this for tags. Sometimes it creates too many categories when you might only want 3-5 for your theme.</li>\n\n\n\n<li>One fun thing is a bunch of the work of this just uses public WordPress APIs, so you can run it against any site! I like using <a href=\"https://distributed.blog/\">distributed.blog</a> as a demo. It&#8217;ll still do all the fun downloading and analysis and everything, you just won&#8217;t be able to make changes.</li>\n\n\n\n<li>I now have a local cache of all my WordPress posts I can do other interesting things with, and that&#8217;s cool.</li>\n\n\n\n<li>The logging and reverting probably still has some bugs in it.</li>\n\n\n\n<li>You can riff with it along the way, so for example, it suggested I get rid of my <a href=\"https://ma.tt/category/audrey/\">Audrey category</a> because it didn&#8217;t have enough posts, and I asked it to look at all the companies on <a href=\"https://audrey.co/\">Audrey.co website</a> and categorize any posts that talk about them as Audrey, which created like 50 more.</li>\n\n\n\n<li>I want to check the GitHub repo for any updates before it starts, and maybe periodically, because it&#8217;s iterating and improving really fast.</li>\n\n\n\n<li>It&#8217;s not the default but the entire thing is way more pleasant if you run it with skip-permissions. So testing I usually run the one-liner, exit, resume with skip.</li>\n\n\n\n<li>You can see some of my prompt history in the Github but I apologize it&#8217;s not comprehensive, I also used Gemini and Codex with this and got lots of value from them.</li>\n</ol>\n\n\n\n<p class=\"wp-block-paragraph\">So, not sure what this is, but please check it out, play with it, submit improvements or ideas, and think about what&#8217;s next. Might host a Zoom or something to brainstorm.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The final thing I say is that this was a very different process of writing software for me. Instead of staying at the computer the entire time, I found myself going away for a bit, napping and dreaming about the code, coming back with new ideas and riffing on them. Maybe I&#8217;ll return to my <a href=\"https://en.wikipedia.org/wiki/Polyphasic_sleep\">Uberman polyphasic sleep days</a>? Nap-driven development?</p>\n\n\n\n<p class=\"wp-block-paragraph\">BTW I have lots of thoughts and feedback for <a href=\"https://github.com/emdash-cms/emdash\">Emdash</a> but I thought this was more interesting, will try to get that out later tonight. One preview: TinyMCE is a regression; they should use <a href=\"https://github.com/wordpress/gutenberg\">Gutenberg</a>! We designed it for other CMSes and would be fun to have some common ground to jam on.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 02 Apr 2026 00:14:51 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:42;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"WPTavern: #211 – Elliott Richmond on WordPress Content Creation, Education, and Pizza Plugins\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=203465\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:107:\"https://wptavern.com/podcast/211-elliott-richmond-on-wordpress-content-creation-education-and-pizza-plugins\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:60931:\"<details>Transcript<div>\n<p class=\"wp-block-paragraph\">[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Jukebox is a podcast which is dedicated to all things WordPress, the people, the events, the plugins, the blocks, the themes, and in this case, WordPress content creation, education, and the unexpected diversion into a pizza plugin.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox, and use the form there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So on the podcast today we have Elliott Richmond. Elliott&#8217;s been deep in the WordPress community for over 20 years, developing since the early days, back when WordPress was yet to be forked from b2. He&#8217;s freelanced, built with multiple CMS systems, and has contributed creatively to the community, including releasing a WordPress advent calendar way back in 2013.</p>\n\n\n\n<p class=\"wp-block-paragraph\">He is an active WordPress developer, content creator on YouTube, and unexpectedly a part-time pizza vendor running a thriving pizza business powered entirely by WordPress tools.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Many listeners will know Elliott for his technical videos, but today we discuss how WordPress has served as the glue for unexpected ventures, like scaling a local pizza business during lockdown, using WooCommerce, Jetpack, and custom plugins. Elliott&#8217;s experience showcases just how flexible WordPress can be, whether for websites, unique ordering systems, or even streamlining business processes for other niches.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Recently, Elliott has been asked by Automattic to create content around wordpress.com, giving him early access to features, and allowing him to share his workflow and insights with a broader audience. He talks about his approach to content creation, balancing scripting versus improvisation, and details his low tech kit from iPhone cameras to DIY lighting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Throughout the episode, Elliott shares how community connections and feedback loops, especially via YouTube comments, shape his work, and he discusses the new opportunities for content creators within the WordPress ecosystem.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re interested in WordPress beyond websites, curious about how to turn technical, know-how into educational video content, or just want to hear about WordPress powered pizza, and who doesn&#8217;t, this episode is for you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;d like to find out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so without further delay, I bring you Elliott Richmond.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I am joined on the podcast by Elliott Richmond. Hello Elliott.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:35] <strong>Elliott Richmond:</strong> Hello. How you doing? Thanks for having me.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:37] <strong>Nathan Wrigley:</strong> You&#8217;re so welcome. Elliott and I have had a little bit of a chat prior to hitting the record button.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Elliott&#8217;s one of those people who has been in my world for many years, because I&#8217;ve been vicariously watching what, this is going to sound a rather sinister. I&#8217;ve been watching what Elliott&#8217;s been doing for several years. And we&#8217;ll get into some of that in a moment. It&#8217;s a pleasure to have you on the podcast anyway. I feel like I know more about you than you will do about me, that&#8217;s for sure anyway. But welcome to the podcast.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:04:08] <strong>Elliott Richmond:</strong> Thank you. Yeah, thank you for having me. I think if you put yourself out there, you are bound to attract stalking of some form.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:04:14] <strong>Nathan Wrigley:</strong> That&#8217;s right. Okay. I hope it doesn&#8217;t come across as that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:04:18] <strong>Elliott Richmond:</strong> No, not at all. Not at all.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:04:19] <strong>Nathan Wrigley:</strong> But will you just give us a little bit of your background? Obviously this is a WordPress specific podcast, so you can dip into your early childhood if you like, but maybe if we constrain it to WordPressy things.</p>\n\n\n\n<p class=\"wp-block-paragraph\">How long have you been using WordPress? What do you do at the moment? And then we can get into some of the fun things you&#8217;re going to be doing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:04:36] <strong>Elliott Richmond:</strong> Yeah, sure. So I&#8217;ve been using, or developing with, wordPress for over 20 years. So pretty much as old as WordPress is, but I was developing before that, building stuff. I&#8217;m self-taught developer, but I was building stuff in the early nineties for bands and stuff that I was in, creating music and just putting stuff out on the web.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But then I realised, when I was working at an agency, it was a design agency, that there was definitely a market for the web effectively, but the company I was working for didn&#8217;t really want to get into it. So eventually when I went freelance, I was able to sort of self-teach myself all of the things I was interested in, which was web development. So I used all of the kind of CMSs like Joomla, Drupal, and eventually found b2 which was forked, ended up being WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So, yeah, started seeing lots of communities popping up, meetups and I just reached out to people. And I&#8217;ve actually featured on WP Tavern before because of releasing an advent calendar I think it was, back in 2013, I think it was Christmas time. And it was basically just reaching out to other developers and asking them for code snippets. It was back in the day when WordPress was kind of, it was a blog but developers were using it in really creative ways like portfolios, and product databases where you had to use the category and tagging system to actually make things work, and then manipulate the templates.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So there was lots of code snippets sort of flying about. So yeah, I just reached out to community and got about 30 developers submitting code, and then just released them as advent calendars.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So, today I am still a developer and develop for WordPress, very passionate about WordPress. I&#8217;m a content creator, create stuff on YouTube, and I&#8217;m also a part-time Pizzaiolo. And if you don&#8217;t know what that is, that&#8217;s basically somebody who makes pizzas.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:06:22] <strong>Nathan Wrigley:</strong> I can&#8217;t ignore that, and we&#8217;re going to get into that in a moment. But I&#8217;ve been having people on a variety of different podcasts for over a decade now, and you are the first, actually, that&#8217;s not true. I was about to say that you are the only person that I&#8217;ve ever interviewed who&#8217;s actually used b2 prior to it becoming WordPress. You are not, because I interviewed Matt Mullenweg once, and of course he, along with Mike Little, definitely used b2 because they forked it to become WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But that really does give me an illustration of, you are right at the beginning. So you were one of the kind of founding members of the community, if you like, and goodness only knows, I&#8217;m sure you had no anticipation of what it was going to become.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:07:02] <strong>Elliott Richmond:</strong> No, not at all. Yeah, Kubrick.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:07:05] <strong>Nathan Wrigley:</strong> Old school. If you know what Elliott&#8217;s talking about, you can join the, what&#8217;s the word for somebody who&#8217;s been around in the community for a really long time? Well, anyway, one of those.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So tell us a little bit about the pizza thing. I don&#8217;t want to dwell on it for too long, if you don&#8217;t mind, but this is such an interesting little story. And curiously, it does have a WordPress spin at the end. So yeah, make sure to get that in as well because that&#8217;s fascinating.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:07:28] <strong>Elliott Richmond:</strong> Yeah, so during COVID, during lockdown, my wife and I just started a pizza delivery thing. Because all the kind of delivery shops were closing down and we have a community in our village and it was like, they&#8217;ve tried my pizzas before. So we thought, well, we&#8217;ll just roll it out and set it up. And people were saying, yeah, send me a pizza. So we thought, okay, well we can sell them to the rest of the community as well. And it was just going to be a temporary thing. Five years later, we employ five staff and it&#8217;s still going strong and we sell it as a licence to other people.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But the WordPress thing is, I mean in a million years I wouldn&#8217;t know that I&#8217;d be doing this five years later, but it&#8217;s all because of WordPress that has allowed me to do this. You know, it uses all WordPress products, it&#8217;s WooCommerce, WordPress itself, and some Jetpack stuff with the WooCommerce app. It glues everything together and it helps us to run a sort of micro business like that. And what has turned into a weekend, temporary thing has turned into a full-time business. So, yeah, it&#8217;s a, I don&#8217;t know if I can tell you any more about it really.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:08:28] <strong>Nathan Wrigley:</strong> Well, you can, you mentioned that you&#8217;ve got a plugin that&#8217;s coming out fairly soon, aligned with people who wish to replicate your pizza business, but in their own locale.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:08:40] <strong>Elliott Richmond:</strong> Yeah, so to just give you the bigger picture, my wife is kind of like a bit of a marketing guru, and she sees opportunities where I can&#8217;t see them. She sees all the blind spots. So this whole model can be replicated by anybody. She didn&#8217;t force me, I was willing to do it, but she made me film all of my steps to make pizzas. So if you don&#8217;t know how to make pizza, there&#8217;s a full course to make it. There&#8217;s a whole module of the marketing that we use. There&#8217;s all secret little tips in there about doing stuff on social media, which I don&#8217;t do. My wife does all that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But I&#8217;ve developed a plugin that works with WordPress and WooCommerce and it stitches everything together. So it&#8217;s got an ordering system, it&#8217;s got a slot system, it&#8217;s got a time-based system, so you can only put certain slots within certain times, and then it&#8217;s got a radius distance. So if you were outside of that radius based on your postcode, you can&#8217;t order pizzas, but you can collect them. And we do get people collecting from miles away that were passing last year, and they&#8217;ve driven a hundred miles to come down for the weekend because they&#8217;re passing to pick up a pizza. Honestly, you wouldn&#8217;t believe it. But I think the furthest somebody&#8217;s come is something like 120 miles. It&#8217;s crazy.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Yeah, so people have been in touch with me like from, last chap was in Norway asking about his, could he use it for his brother&#8217;s bakery? And I said, yeah, absolutely. So anything that&#8217;s got like a restricted delivery zone, and maybe you want to just do it at certain times, you can do it. But you don&#8217;t even need to use the slot system, but you can set the radius distance. So if you want to do local deliveries, you can set a four mile radius, five mile, ten mile, whatever you want to set. Anything is doable really. Yeah, you can use the plugin.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that&#8217;s kind of like the freemium Pizza Pilot. And then there&#8217;s a Pro version that we actually will bundle with our licensees. And we&#8217;ve got, it&#8217;s not like a franchise, it&#8217;s, you know, they buy the whole model once, and then they get the plugin bundled in. And, yeah, I&#8217;m just kind of like fine tuning it so that I can manage it. So if pizza does take over my life, I&#8217;m still, got my foot in WordPress and developing this product. So I&#8217;m happy about that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:10:37] <strong>Nathan Wrigley:</strong> That&#8217;s so interesting that you have WordPress as the sort of fulcrum of this entirely different side of your life, really. And it feels like it&#8217;s more than like a hobby project at the moment. It feels like it&#8217;s the underpinnings of a lot of what you do, albeit maybe the WordPress community don&#8217;t know about it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But also curious that, and again, I might be reading between the lines, maybe you launch the pizza business and then kind of retrofit your procedures into your own dog fooding plugin, which now you are deciding to sell.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But the fact that the technology stack that you knew inside out was able to facilitate that, you know, and a website can handle things like geolocation, that a website can handle things like payment, and the ability to add ingredients and things like that. All of that enabled you to launch that business, which is just so interesting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Because most people who use WordPress, I doubt ever have that experience in life. You know, maybe they&#8217;re building things for clients, or they try a little hobby project. But you&#8217;ve got, I don&#8217;t know, it just sort of perfectly slotted in and, well, serendipity seems like the right word. Everything just sort of seems to slot in perfectly, and how wonderful.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:11:46] <strong>Elliott Richmond:</strong> Yeah, I think it all kind of happened at the same time, because I just mentioned to Rachel about, you know, during lockdown these businesses are shutting down and people are going to pivot. Because I was talking to the WordPress community and they were talking about how their businesses were pivoting, like their restaurants. And I said, I could set this up as a website. So it all came together kind of all at once really.</p>\n\n\n\n<p class=\"wp-block-paragraph\">One thing I&#8217;d have to say is that I like doing complex things with WordPress, and I&#8217;m really interested in the way that people do stuff with WordPress. So we have somebody that comes to our Meetup that is a gardener, and they come religiously to our Meetup. You&#8217;d think, well, why is a gardener coming to the Meetup? Well, it&#8217;s because they run their whole invoicing system and business, the gardening business, through WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So it&#8217;s like, oh, that&#8217;s interesting. So there&#8217;s so many different things you can do with WordPress. So the one thing I&#8217;m grateful for is all of my experience that WordPress has given me and the opportunities in terms of my career, being able to sell, you know, development packages to clients, and picking up complex jobs in that sense. Because without, it wouldn&#8217;t be the glue for the pizza thing, and it wouldn&#8217;t have happened that easily.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:12:49] <strong>Nathan Wrigley:</strong> Right. Genuinely, absolutely fascinating. I think we could probably do the entire podcast about that, but there is another story to tell. As I said, I&#8217;ve been looking at Elliott online for quite a while and then, I don&#8217;t know when it was, but it was certainly quite recently, we are recording this in March, 2026, quite recently that I learned that you are going to be working with Automattic. I don&#8217;t know if it&#8217;s for Automattic, but certainly for the wordpress.com side of things. I could spoil what you are doing and misrepresent what it is. Probably best to just hand it over to you, and tell us what this gig is, this project that you&#8217;ve got running through 2026.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:27] <strong>Elliott Richmond:</strong> Yeah, so I have to shout out to Michelle Frechette because she basically reached out to me and suggested an introduction with Stacey Carlson, who is Automattic&#8217;s Affiliate and Influencer Director. And she&#8217;s obviously picked up some of my videos and she just said to me that, do you fancy us sponsoring a video or two about wordpress.com and how I felt about Automattic products? I said, yeah, why not? I use them all the time, every day. So it&#8217;s definitely up my street.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So I put some stuff together and she basically just told me that the Automattic leadership team, which directly is Matt down, were broadly supporting content creators. So yeah, I was on board with it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And my mind just went on overdrive. Basically, Stacey said to me, would you like to do this thing? And I was like, yeah. She said, okay, well, we&#8217;ll have a chat in a couple of days or whatever. And I was like, I put concepts together and I sent about three or four different ideas. And it was like, yeah, okay, let&#8217;s do this. And it&#8217;s basically how I use WordPress, what I did, the whole pizza thing, what I do from day to day.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I put these videos together and then it created another opportunity and another introduction to a lady called Brit Solata, who&#8217;s head of Influence Marketing. Big inspiration for me is another guy called Jamie Marsland, who&#8217;s actually the head of the wordpress.com YouTube channel, because he basically raised his profile by using WordPress and turning hard concepts like using the Block Editor into really easy to understand videos.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And he had the genius idea of creating the speed challenge, which was kind of viral. Again, he lives down the road from me, believe it or not, less than five, six miles away. So there&#8217;s a funny story behind that. We&#8217;ve known each other for like 15 years, connected through social media and whatever channels there are that we used to use. And we actually met for the first time, face to face, at WordCamp Europe in Greece. And it always tickles me because the first thing he said is like, we&#8217;ve known each other for years, but this is the first time we&#8217;ve met, and we have to come over the other side of Europe. So it&#8217;s not great for our carbon footprint, which always makes me chuckle.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Yeah, he was a great inspiration. And since then we went out for a coffee or two and he inspired me really to start doing my YouTube stuff. And I think that&#8217;s really what got me recognised through Michelle, Stacy, and Brit. And then Britt suggested that we do something for the rest of this year. So I&#8217;m going to be doing videos about wordpress.com, what&#8217;s coming up.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress has always been a moving target. It uses multiple different types of technology, right? So there&#8217;s always different things happening and changing. And with the advent of AI, there&#8217;s a lot of stuff coming into the whole project. So, yeah, that&#8217;s kind of where we&#8217;re at.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:16:09] <strong>Nathan Wrigley:</strong> I have a lot of questions around that actually. So the first thing I&#8217;m going to ask is, is the intention to make long form content, or are you hoping to make more short form content? And really behind that question is what you just said about the fact that WordPress is in a real period of flux. On the .org side, we&#8217;ve got WordPress 7 coming around, which is going to be transformational, but I also feel that any video that gets made to coincide with 7 is quickly going to go out of date because we&#8217;re in such a rapid period of flux.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So just conscious about that, really, whether or not the content that you are going to be creating, and forgive me for using this word, is more disposable, if you know what I mean? So the kind of content that you&#8217;ll throw together in the anticipation that in 4, 3, 2 months time, you might have to reshoot it again. So, yeah, just wondering what the constraints are on the kind of content that you&#8217;re going to be making?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:17:01] <strong>Elliott Richmond:</strong> There aren&#8217;t really constraints in that sense, but I think the whole nature of WordPress is ideal for that kind of scenario. So we are going to do long form content and then spinoff of that is going to be the short form as well, because you can just do that with the modern tech that you can use today anyway.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But yes, I think if you&#8217;re working in the Core team and you&#8217;re doing documentation, and it&#8217;s always been a thing, getting documentation out has always been a problematic thing. And if you&#8217;re working on something and you&#8217;re deep into it, it&#8217;s difficult to get that stuff out.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I think over the years it&#8217;s got better because you&#8217;ve got prominent people in Core, in the team, working at Automattic that are pumping stuff out. Justin Tadlock and the other chaps and Birgit is putting stuff out with Gutenberg Times and things like that. So it has got a lot better, but definitely there is an opportunity for content creators to fill a gap in terms of new things that are coming, what&#8217;s going to be changing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And also the way that people consume that content because YouTube and all the social, other social platforms, not that they&#8217;re great, TikToks and all that, but there&#8217;s definitely an opportunity for that content to be absorbed by different people. So there&#8217;s definitely a gap there for content creators to make people aware about those changes and new developments that are coming to WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:18:22] <strong>Nathan Wrigley:</strong> I&#8217;m in the lucky position in that for this podcast there isn&#8217;t really a laundry list of things that I have to cover. It&#8217;s very much up to me what I wish to have on the podcast. So you are an example, you know, decided to do this, and here we are doing it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But I did wonder if you were, you know, you mentioned some names there over at Automattic. I don&#8217;t know if there&#8217;s going to be some things that they will require you to do because that&#8217;s in line with what .com has just released or what have you. Or if you really are, you know, the reins are off, do what you like Elliott and just make sure that you post us and tell us what&#8217;s going on.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;m imagining there will be some sort of guidance and, okay, this thing&#8217;s about to launch, it would be really welcome if you produce the piece of content explaining why we&#8217;ve done it, and how it works and so on.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:19:03] <strong>Elliott Richmond:</strong> There&#8217;s no guardrails in that sense. It feels very fluid and flexible. Yes, there are kind of like things, we&#8217;d love you to do this, and I&#8217;m more than happy to do that because it&#8217;s definitely on my street anyway.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The products that are sort of being talked about are products that I use every day, so it has synergy, you know? It&#8217;s not like I&#8217;m having to do something that I wouldn&#8217;t be comfortable doing. It&#8217;s stuff I love doing and I love teaching other people anyway. So in terms of that whole community thing, I think when communities come together, the most I get out of it is actually learning from other people, not just teaching them.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And actually just by teaching somebody, or telling somebody about something, they give you feedback and the feedback loop there is super important, especially for a project like WordPress. Without that feedback loop, potentially, it&#8217;s not going to be a thing that anyone will use anyway. So just by doing something with the community or publishing something is useful feedback.</p>\n\n\n\n<p class=\"wp-block-paragraph\">There may be something that is sort of created and developed that I don&#8217;t necessarily agree with, but I can still put it out there, say whether I like it or don&#8217;t like it, and then ask somebody, you know, what&#8217;s your feeling? Have you used it? What&#8217;s your feedback? Get some comments. That is feedback. And that&#8217;s how you improve things.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:14] <strong>Nathan Wrigley:</strong> YouTube is a phenomenal feedback loop actually. I mean, I know you&#8217;ll probably be getting feedback from within Automttic and what have you as well, but I long for the comments on a WordPress blog to be like the comments on a YouTube video. It seems that everybody&#8217;s quite willing to get the keyboard out and hammer out thousands of replies on a YouTube video. It really does capture that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so, especially if during the content you provoke the audience to comment, and to give you feedback, because you may well be making another piece of content, which will be guided by the comments and what have you. I think it&#8217;s amazing for that. And kind of like pretty, pretty untapped. Usually when you watch content, it is just, okay, I&#8217;ve decided what I&#8217;m going to do. There it is. It&#8217;s an isolated, atomised piece of content. But the idea of going and asking for, what shall I do next? Or something akin to that is really great. And I hope that works out for you. I fully anticipate that it will, because like I said, the comments are usually fairly voluminous.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:21:09] <strong>Elliott Richmond:</strong> Yeah, it&#8217;s interesting because some of the comments actually inspire you to create your next piece of content. So it&#8217;s always good. Sometimes it is difficult because you can see that it&#8217;s negative feedback. But actually I think that negative feedback is a positive thing because you can respond in a positive way. Or you can just take that feedback and then feed it back into the ecosystem and that&#8217;s how things get changed. So any negativity is a positivity in my book.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:21:35] <strong>Nathan Wrigley:</strong> Yeah, nice. I think you have to armour yourself with things like that when you go on social media and post content, don&#8217;t you? Because it doesn&#8217;t matter how perfect it is, and how well aligned it is, there&#8217;s always somebody lurking somewhere who is willing to derail your day with a comment like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Are you going to be doing this then on official, so you&#8217;ve made the content, you&#8217;ve created the video, and yada yada. We can get into the process of that in a moment. I&#8217;d be kind of interested to know what you do. Are you going to be posting this on official WordPress channels, or is this that you are being hired to create the content and then put it out on your own channels? Or is it, does it come with the official stamp of the wordpress.com YouTube channel or something like that?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:22:13] <strong>Elliott Richmond:</strong> No, it&#8217;s on my channel for my audience. So I&#8217;m free to do whatever I want really. I can do my own stuff but there is a, kind of an agreement we have to meet certain months and content that will be aligned with whatever&#8217;s happening at wordpress.com or at Automattic. But yeah, there&#8217;s no restriction. It&#8217;s kind of on my channel to my audience.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:22:33] <strong>Nathan Wrigley:</strong> Is it very much then going to be YouTube, like screen shares of the kind of things that you&#8217;ve been doing with a code editor or in the backend of WordPress, or a plugin that you&#8217;ve installed and have played with or what have you? But obviously on the .com side of things as opposed to the .org side of things.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:22:47] <strong>Elliott Richmond:</strong> I don&#8217;t want to give too much away, but I&#8217;m given kind of a little bit of early access to stuff that, I found it difficult to find it but it is available, you can get to it, but I needed some pointers. But it&#8217;s going to be a mix of technical stuff. You&#8217;ve seen my stuff, I&#8217;d like to get technical content simplified and I use graphics. And, I mean, if I look at my first stuff, it was nowhere near as polished as it is today. but I like to use animation.</p>\n\n\n\n<p class=\"wp-block-paragraph\">There&#8217;s difficult concepts to get over, especially with templating and patterns and template parts and things like that. And if you can simplify that to users, to use this stuff with more knowledge. But there&#8217;s also stuff about AI that&#8217;s, I mean it even confuses me today, like MCPs and, what&#8217;s that? And it&#8217;s like large language models and things like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So there&#8217;s complex stuff that I&#8217;m really looking forward to getting my teeth into because I can try and simplify it. And that&#8217;s what I like doing in terms of like graphics and analogies. And hopefully it makes sense to people.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:23:46] <strong>Nathan Wrigley:</strong> So it&#8217;s going to be, I guess the one word that maybe I would encapsulate it as is educational. The idea is that you come in, learn a thing, or multiple things, and then go away. It&#8217;s not just that, oh look, here&#8217;s the latest new feature that&#8217;s shipping. It&#8217;s more, look, here&#8217;s the feature, but also here&#8217;s how you get to it and how you navigate it and what it does. And if you want to implement it, you must do this, yada, yada, that kind of thing. So educational.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:12] <strong>Elliott Richmond:</strong> Yeah, absolutely. There&#8217;s lots of other things happening as well that are specifically for developers and not necessarily for wordpress.com. But yeah, engineering those things and putting those together to make something work in the way that you want it to, there is a technical barrier to that. So if I can simplify that and help others to get up and running, then great.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But there&#8217;s things like Xdebug that are not enabled by default in the Studio app that I think are really useful. Now I&#8217;ve used Xdebug for debugging my code for many years and I honestly cannot do without it. And I didn&#8217;t even know it was there, you know, that&#8217;s how hidden it was, until I saw a tweet like the other day, and it was, I think it&#8217;s recently been rolled out, but I&#8217;m like, I am itching to do a video on that, so that I can just let people know how to use it and what it&#8217;s beneficial for.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:56] <strong>Nathan Wrigley:</strong> Yeah, you strike me as the kind of character that&#8217;s not going to be short of things to do content about. It&#8217;s more, which comes first. And I think that&#8217;s such a nice gig for you as well, in that you&#8217;re obviously a very curious individual. You know, you&#8217;ve been making videos for, this is going to come out the wrong way, but, you know, for no reason, if you know what I mean? You know, there was nobody prodding you with a stick saying, Elliott, we need another video now because you&#8217;ve been paid for it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You were doing it because that&#8217;s something that you found enjoyable, and you like the experience of doing all of that. And then somebody comes along and says, you know what? I think we could well do with paying you for this. That must have been kind of, almost manna from heaven in a way.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:25:34] <strong>Elliott Richmond:</strong> Absolutely. I mean, I feel so fortunate. I&#8217;m so grateful to Michelle Frechette for reaching out to me and making that contact because, yeah, I mean, it&#8217;s right up my street. You&#8217;ve seen, I&#8217;ve got guitars around the studio and I think it&#8217;s like, I&#8217;m the sort of person that I think it&#8217;s good to learn something new every day, regardless of what it is. And yeah, you have to be intrigued by something.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And particularly with code and technology, it&#8217;s changing all the time. You can do things in different ways. Very much the same as just fingering around a fretboard and trying to find that lick, or that nice harmonic tone that you never found before. And you think, ah, I can do this. I&#8217;m going to show my bass player that I can do this, or my guitar player, or whatever. You know, it&#8217;s a bit like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And you get excited about the littlest things that maybe are not so exciting to a lot of people, but they are to me, and that&#8217;s why I do it. And if I can just impart that on somebody, that&#8217;s a bonus to me. And I do get that feedback on YouTube. So I&#8217;m always so grateful when I get positive feedback like that. So, yeah, long may it continue. And I&#8217;m not going to stop doing it because I find it fascinating and I really enjoy it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">There are many stages to doing a video. You have to figure out what you&#8217;re going to talk about, the script, which I didn&#8217;t used to do. It was just kind of like, I know this thing, so I&#8217;m just going to jump on. But I now script things, break things down into concepts, and then know when I&#8217;m going to do some motion graphics. Then I do the headshots, and then I do the editing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And when I&#8217;m done editing, I&#8217;m not done editing in like one day, I just do a couple of hours and I go back into the house and I just tell Rachael, I say, I absolutely love editing. It&#8217;s just like, it just really excites me. So it is just these little things. Not necessarily about WordPress, but yeah, figuring out how to get a concept across. And then I&#8217;ll sit and I&#8217;ll bore the tears off Rachael, try and explain this stuff to her, and she&#8217;s just patiently listening to me, you know, so I can get it out of my head.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:27:19] <strong>Nathan Wrigley:</strong> No, I think that&#8217;s the most credible way of getting to the perfect simulation of what it is you&#8217;re trying to educate people with. Because you trip over yourself, don&#8217;t you? And you realise, okay, that second point should have been the third. And the third should have been the second. And there was a better way of explaining that. I think it&#8217;s great that you do it that way.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I&#8217;m also, pleased is the wrong word, but I&#8217;m curious that you script it as well. Because I know that the temptation is often easy, isn&#8217;t it? It&#8217;s just, okay, I know this stuff inside out, I&#8217;ll just go for it. That extra hour, two hours, three hours, whatever it may be, of disciplining yourself to write it down, I think you go a million more miles with that content. You know, you refine it, you work it through, you cut out the additional words that are not needed, that just sort of demonstrates to me that you are really, really serious about it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:06] <strong>Elliott Richmond:</strong> I say scripted, loosely scripted. It&#8217;s scripted not to the absolute T. It&#8217;s kind of like flashcard prompts.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:10] <strong>Nathan Wrigley:</strong> Oh, no. No, no, no. Sorry. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:13] <strong>Elliott Richmond:</strong> But there&#8217;s the structure, let&#8217;s say. And sometimes I do word for word. But if I go off piste, if I&#8217;m recording, I&#8217;m like, yeah, I&#8217;m just going brush over that. It&#8217;s not that important. It&#8217;s just an um or an ah, or an and and a the that shouldn&#8217;t be there, but whatever. I mean, if I watch back some of my stuff, I&#8217;m like, oh, did I really say that? I&#8217;m my worst critic, I guess.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:31] <strong>Nathan Wrigley:</strong> The trick there is never to watch or listen to your own stuff.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:35] <strong>Elliott Richmond:</strong> Yeah. Yes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:37] <strong>Nathan Wrigley:</strong> The problem is, if you are self editing, you have to listen to yourself, you know, for every hour that I record, I end up listening to myself for probably about four hours. It is purgatory. For example, the sentence that I&#8217;ve just said, I will listen back to and I will be ruing the day that I said it. It&#8217;s curious.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Given that it&#8217;s on the .com side of things, and if, dear listener, you&#8217;re not familiar, we have sort of like this bifurcation, if you like, of WordPress. We have the .org side, which is the way you can go, wordpress.org, and you can download it and put it on a server and put it on your local machine and do what you like with it. And then the .com side, which is where Elliott&#8217;s work is going to be mostly living I guess, is the hosted side. So you go and you pay a monthly fee and you have access to WordPress over there, so you don&#8217;t have to think about the hosting or anything like that, that&#8217;s just taken care of.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Do you get a sense that there&#8217;ll be like commercial pressure there? That&#8217;s maybe getting to territory that you don&#8217;t wish to get into, I don&#8217;t know. But will, for example, you have to create content around certain features because it&#8217;s shiny and new? So instead of it being educational, it might slip into the more promotional, and I&#8217;m doing air quotes as I say that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:29:45] <strong>Elliott Richmond:</strong> In my experience, little experience working with the guys at the moment, there&#8217;s been none of that. It&#8217;s literally, you have the free reign, do what you want. There is a benefit of putting a script together in that sense, because you can iron things out if you need to. But in all honesty, of the 10, 15 scripts I&#8217;ve already sent through, I&#8217;ve only had minimal feedback. They said, great, it looks great. Let&#8217;s go with it. And also, if it&#8217;s a new shiny thing, show me. I want to know about it. I want to tell others about it as well, you know?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:30:11] <strong>Nathan Wrigley:</strong> Right. So the overlap there is welcome to you, which is quite nice, isn&#8217;t it? It&#8217;s new, it&#8217;s interesting. I would like to mention it anyway.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:30:17] <strong>Elliott Richmond:</strong> There is also another point. I think there&#8217;s a misconception between wordpress.com and WordPress, the standalone software. Because effectively it&#8217;s the same thing. When you use something like the Studio app, you&#8217;ve still got your local files and you can still develop your own stuff. You can get as complex as you want. You are just literally hosting it with the people that make this software. And you then know that you&#8217;re going to get the performance, you&#8217;re going to get all of the security stuff, you&#8217;re going to get all the benefits of hosting with a, on a platform that know the software. So there&#8217;s a win-win situation there in my opinion.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:30:52] <strong>Nathan Wrigley:</strong> So you were mentioning earlier, Jamie Marsland, just down the road from you, who&#8217;s the head of WordPress YouTube. Obviously kind of a prolific content creator himself, and then got taken on by Automattic to carry on that journey. There&#8217;s obviously now you. I wonder if you&#8217;ve got any thoughts on how WordPress, and you might read Automattic in here or .com or whatever the right word is. I wonder how you view the seriousness with which they&#8217;re taking content creator content.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Because again, if I rewind the clock three or four years ago, it felt that there really wasn&#8217;t much coming out that had that kind of official stamp. We were kind of left to our own devices. We were going into Slack and reading comments, or we were going into GitHub queues for plugin developers and things like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But it does seem that at some point in the last four or five years, somebody somewhere said, wait, no, video is it. We really have to invest in video. And it feels like you&#8217;ve been caught up in that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">There&#8217;s no real question there. It&#8217;s more just an observation that video content by people who obviously are out in the community doing this with a serious intention. It&#8217;s more than just a hobby. It&#8217;s something they&#8217;ve got a track record of doing seriously. I wonder if you&#8217;ve spotted that trend as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:32:05] <strong>Elliott Richmond:</strong> Yeah, absolutely. I mean, I often look up stuff on YouTube. It used to be Google. How do I, I don&#8217;t know, mitre some wood together? You can go to YouTube now and you can find all of this stuff. Or how do you make the perfect naan bread or the perfect pizza, let&#8217;s say? So yeah, YouTube is definitely, in the last, I actually don&#8217;t think it, it&#8217;s always been there, but it&#8217;s probably, it&#8217;s only become sort of more prominent on my radar, I guess. So if that&#8217;s a result of what&#8217;s been happening organically, then yeah, I&#8217;ve just been sucked into it. But, yeah, I think it&#8217;s always been there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You always get from YouTube content creators about how much more difficult it is, I guess, because there&#8217;s more people doing it, so they&#8217;ve got less money to give people. But honestly, I&#8217;m not in it for the financial reward anyway. I mean, I do get paid ads and stuff, but it&#8217;s peanuts every three months, so I&#8217;m not in it for that at all.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So yeah, it&#8217;s definitely on my radar basically. I mean, in terms of editing and software, I still look up stuff. You know, even whether it&#8217;s WordPress or whether it&#8217;s command line stuff. Particularly now, if you drop AI into the title, you&#8217;re going to get loads of stuff.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:33:10] <strong>Nathan Wrigley:</strong> Yeah, I mean, more and more if you go and ask a question of Google, you&#8217;re going to get the AI answer first, but then you&#8217;re just going to get like a big row of YouTube videos. You know, if you ask it a question beginning, how do I, or something along those lines, the AI often comes first.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;m actually using a different search engine now. I use one called Kagi, which was actually by coincidence developed by the guy who used to run Manage WP, who then sold it and moved on to make this search engine. There&#8217;s another success story coming from the WordPress space. But if you ask it a question, you get the AI generated sort of response over three or four lines, and then after that, just a cavalcade of YouTube videos. And it really, I think, has become the default.</p>\n\n\n\n<p class=\"wp-block-paragraph\">What I&#8217;m finding interesting about that is, I think that wordpress.com in this case, but you could read Automattic, are kind of putting their money where their mouth is and doing it in an interesting way.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So rather than, let&#8217;s say, employing a team of content creators to do this, this, this, this, and this, they&#8217;re asking people like you to just get on with it. Just do what you were doing. I think that&#8217;s really interesting. And it&#8217;s hard to encapsulate what I&#8217;m saying there, but there&#8217;s a real level of trust. You know that you&#8217;ve got to do things, but nobody&#8217;s micromanaging you to tell you what to do. It sounds like nobody&#8217;s giving you, okay, we want this piece of exact content, and this one and this one and this one. It&#8217;s more, Elliott, you&#8217;ve got a track record, you&#8217;ve proven yourself, now crack on, but we&#8217;ll assist from the financial point of view. I think that&#8217;s a really nice model of allowing people like you to do what you do, and the trust that you&#8217;ve built up is all that was needed to get you started on that journey.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:34:47] <strong>Elliott Richmond:</strong> Yeah, there are kind of, who this is for, what&#8217;s good to do, what isn&#8217;t great to do. So there is, not guardrails as such, you&#8217;re given complete flexibility, but you are given a kind of like a brief, not template, it&#8217;s not template, it&#8217;s a, what&#8217;s this for? What&#8217;s the target?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:03] <strong>Nathan Wrigley:</strong> Like an avatar kind of, something like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:05] <strong>Elliott Richmond:</strong> Yeah. Yeah, an avatar. I don&#8217;t find that restrictive in any way. If I did, I wouldn&#8217;t be doing it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:10] <strong>Nathan Wrigley:</strong> No, that&#8217;s really helpful.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:11] <strong>Elliott Richmond:</strong> Yeah, exactly.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:12] <strong>Nathan Wrigley:</strong> Yeah. But you&#8217;re given a lot of rope. It does sound like you&#8217;ve got a lot of leeway to do what you like. I mean, maybe there&#8217;s constraints around, you know, let&#8217;s not make content about the UI of Wix or Squarespace or anything like that. You know, that&#8217;s probably out remit.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:28] <strong>Elliott Richmond:</strong> That goes without saying.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:29] <strong>Nathan Wrigley:</strong> Yeah, yeah. But certainly from my point of view, doing this podcast, WP Tavern, I can&#8217;t really sum it up, but I have that same freedom. I can have who I like on, nobody&#8217;s telling me what I can do and when it should be done. It was just a case of, okay Nathan, you&#8217;ve done podcasting, we would like you to do this one. And it sounds like a similar kind of offer was made to you, but on the video side. The trust behind that is hard to communicate, but it feels so nice.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:57] <strong>Elliott Richmond:</strong> Yeah, absolutely. I mean, I&#8217;ve always said, because I&#8217;ve worked on my own for such a long time, since I was in my twenties, and I won&#8217;t tell you how old I am, but it&#8217;s been a few decades now, I literally am unemployable. I do work on a remote basis for a company, but it&#8217;s on a very minimal tech lead responsibility kind of arrangement. But I could not go into an office. I&#8217;m just conditioned not to be, someone breathing down my neck. I&#8217;ve just been conditioned to have that freedom and creativity that I love. And definitely without a doubt, I&#8217;ve been given this opportunity in the same respect. So I&#8217;m absolutely stoked about it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:36:34] <strong>Nathan Wrigley:</strong> Yeah, I think that&#8217;s really lovely. You&#8217;ve got that history. And I think we see that in the community a lot. You know, you&#8217;ve got a history, and it&#8217;s your turn to shine, if you like.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Okay, now the nerdy bit, right at the end. I want to know what your process is. Obviously being a content creator myself, I&#8217;ve got a whole load of software that I use and I flit around, but I&#8217;ve kind of stabilised on a few key pieces of software, which enabled me to do that journey.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;m sure that there&#8217;s going to be people listening to this who have thought to themselves, I too would like to make videos, and I&#8217;m curious, what is your tech stack? I mean, we don&#8217;t need to go into absolutely everything, but I&#8217;m curious, what are the 3, 4, 5, whatever it may be, essential things that are either on your desk, or on your computer that make the whole thing easy and possible?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:37:18] <strong>Elliott Richmond:</strong> My tech stack is so low key, it&#8217;s unbelievable. My lights, if I explain my lights to you, I&#8217;ve got basically a cat food pouch box, which is like six inches by four with a hole cut out of it, resting on an LED light with a bit of tissue paper over it. It&#8217;s that low key, low tech.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:37:34] <strong>Nathan Wrigley:</strong> So it&#8217;s like a small shoebox with a hole cut in with tissue paper diffuse the light.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:37:39] <strong>Elliott Richmond:</strong> Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:37:40] <strong>Nathan Wrigley:</strong> That&#8217;s so great. That&#8217;s so cottage industry. I love that. Yeah, because you could of course buy the $150 equivalent, but you know, the cat food box is lying around. That&#8217;s brilliant. Oh, I hope this keeps going. I hope you got more of these.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:37:55] <strong>Elliott Richmond:</strong> If I could just turn the camera round. And the other thing is just an iPhone. I just use my iPhone. My iPhone is literally sitting on my computer now. So it&#8217;s good enough to do what I need to do with it. At some point it will upgrade, but for anybody who wants to do this out there, you know, you don&#8217;t need much kit.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In terms of the software, I just use the Notes app and I just jot down my ideas. I actually use the accessibility keyboard shortcut. So I literally, what I do is tap the key and just speak into my mic about the idea that I want to get across. And then that&#8217;s my brain dump. And then I&#8217;ll take that, read it back, break it down. It&#8217;s all in my own words, I then just get AI to polish it a little bit, so it kind of gives me the bare bones of my script. And then that gets me like 60, 70% there. But it&#8217;s literally my brain dump that&#8217;s polished, and then I repolish it again. So that&#8217;s one key bit of legwork that gets me going quickly.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;ve picked up a lot of kit over the years from just producing music. I&#8217;ve got some NS-10s in front of me, studio monitors, so I can do all my sound balancing and stuff. The other key bit of software is DaVinci Resolve, which is, it&#8217;s got all of the motion graphics in it. It is a bit of a head spinner to get into it, but there&#8217;s lots of resources out there that can help you get to where you want to be.</p>\n\n\n\n<p class=\"wp-block-paragraph\">There&#8217;s lots of stuff out there that you can, like library stuff that you can subscribe to and pull in. But I&#8217;m always reluctant to do that because I&#8217;m the sort of guy that, I want to, even if it&#8217;s code, I want to get into it. I want to understand exactly how it works and do it myself. So working with nodes and animation in that sense has been, it&#8217;s been a big learning curve, but I&#8217;ve absolutely loved it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And then just the editing is like DaVinci Resolve. And it has everything in it. I pay a licence for it because I want all the whistles and bells, but you can use the free version and I just cannot believe what you can get away with, with the free version. You get all of the motion graphics, you get all of the audio, you get the colour correction, plus all of the editing suite. It&#8217;s incredible.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;m just looking around to see what other stuff I&#8217;ve got, but yeah, that is literally about it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:39:52] <strong>Nathan Wrigley:</strong> I think you&#8217;ve encapsulated perfectly. I mean, really you need a computer with a bit of editing software, and there&#8217;s many. Some free, some much more expensive. You can certainly pay a fortune for some editing software. But also camera, a little bit of lighting, I guess a backdrop and a quiet room would help. But that&#8217;s kind of really all that it takes. The key bit, of course, the bit that you are not mentioning of course is that script bit. That&#8217;s where the magic happens.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And people like you are able to turn difficult things into easy to consume things. For people like me who consume it, it all just looks so straightforward and easy. But I&#8217;m well aware that in the background there&#8217;s probably quite a lot of soul searching and rehashing and rethinking and you were saying, explaining to your wife and re-explaining to your wife and so on.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so whilst the software and the iPhone camera and all of that are necessary to make it happen, I think the bit which makes your stuff, and people of your calibre&#8217;s stuff, stand out is that bit inside your head. The bit which only you can do in the way that you do it, you know? I&#8217;m grateful for all the stuff that you&#8217;ve done for many years, and long may it continue. You&#8217;re carrying on throughout 2026, I think is how it&#8217;s framed at the moment.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:41:02] <strong>Elliott Richmond:</strong> Yep, or up to December at least that&#8217;s the arrangement. But I&#8217;m also allowed to do whatever, you know, my own stuff as well. So if you spot a video about me making pizza or preparing dough, somehow I can thread WordPress into that, I will. I probably can actually because I&#8217;ve got a dough calculator.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:41:20] <strong>Nathan Wrigley:</strong> With your pizza plugin, I&#8217;m sure that there&#8217;ll be ways of getting those messages across. I think we&#8217;ll knock it on the head there, as we say in the UK. Best of luck. I&#8217;m sure luck is not the thing that you need, but I hope it goes well, and I hope that you enjoy it and that obviously the crowd of people who come along gain a lot of knowledge from everything that you&#8217;ve done.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Just before we go, I think we should probably say where we find you online, where that YouTube channel is, or your website, whichever you prefer. Both if you like.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:41:46] <strong>Elliott Richmond:</strong> Yeah, you&#8217;ll find me on YouTube, which is elliottrichmondwp. I do have an Elliott Richmond, which is all of my personal stuff, so don&#8217;t get that confused with the WordPress stuff. It&#8217;s elliottrichmondwp. And you can find my blogs and my brain dumps on elliottrichmond.co.uk. And that is double L, double T by the way.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:42:07] <strong>Nathan Wrigley:</strong> Yeah, as I was typing your name in, subconsciously it always ended up with one T. I don&#8217;t know what was going on there. But all the Elliots in my life have got a single T. E-L-L-I-O-T-T, and then Richmond, as you might imagine.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you go to wptavern.com and you look for the Elliott Richmond episode using the search functionality, then you&#8217;ll get that episode, I&#8217;m sure. And all of the links for anything that we have mentioned, so the YouTube channel and the website, what have you, that will all be in there, one click. Along with a transcript of everything that we&#8217;ve talked about as well. So Elliott Richmond, thank you. Good luck with 2026 and thanks for coming on the podcast.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:42:46] <strong>Elliott Richmond:</strong> You&#8217;re welcome and thank you so much for having me.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:42:48] <strong>Nathan Wrigley:</strong> You&#8217;re very welcome.</p>\n</div></details>\n\n\n\n<p class=\"wp-block-paragraph\">On the podcast today we have <a href=\"https://elliottrichmond.co.uk\">Elliott Richmond</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Elliott’s been deep in the WordPress community for over twenty years, developing since the early days, back when WordPress was yet to be forked from b2. He’s freelanced, built with multiple CMS systems, and has contributed creatively to the community, including releasing a WordPress advent calendar way back in 2013. He’s an active WordPress developer, content creator on YouTube, and, unexpectedly, a part-time pizza vendor, running a thriving pizza business powered entirely by WordPress tools.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Many listeners will know Elliott for his technical videos, but today we discuss how WordPress has served as the glue for unexpected ventures, like scaling a local pizza business during lockdown using WooCommerce, Jetpack, and custom plugins. Elliott’s experience showcases just how flexible WordPress can be, whether for websites, unique ordering systems, or even streamlining business processes for other niches.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Recently, Elliott has been asked by Automattic to create educational content around WordPress.com, giving him early access to features and allowing him to share his workflow and insights with a broader audience. He talks about his approach to content creation, balancing scripting versus improvisation, and details his low-tech kit, from iPhone cameras to DIY lighting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Throughout the episode, Elliott shares how community connections and feedback loops, especially via YouTube comments, shape his work, and he discusses the new opportunities for content creators within the WordPress ecosystem.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you’re interested in WordPress beyond websites, curious about how to turn technical know-how into educational video content, or just want to hear about WordPress-powered pizza (and who doesn’t), this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Elliott featured in WP Tavern before:  <a href=\"https://wptavern.com/24-wordpress-snippets-til-christmas-submissions-open-for-2019\">24 WordPress Snippets ’til Christmas, Submissions Open for 2019</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://www.youtube.com/pootlepress\"> Jamie Marsland on YouTube</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://gutenbergtimes.com\"> Gutenberg Times</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://xdebug.org\"> Xdebug</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://kagi.com\">Kagi Search Engine</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://www.blackmagicdesign.com/products/davinciresolve\"> DaVinci Resolve</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://www.youtube.com/@elliottrichmondwp\">Elliott&#8217;s YouTube channel</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://elliottrichmond.co.uk\">Elliott&#8217;s website</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 01 Apr 2026 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:43;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:55:\"Open Channels FM: Reducing Stress in Website Management\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551246\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"https://openchannels.fm/reducing-stress-in-website-management/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:182:\"Website managers face overwhelming tasks daily, necessitating prioritization, proactive communication, and streamlined processes to reduce mental load and ensure client satisfaction.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 01 Apr 2026 13:34:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:44;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"Open Channels FM: Building Better Web Security Through Layered Strategies and Collaboration\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551715\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:98:\"https://openchannels.fm/building-better-web-security-through-layered-strategies-and-collaboration/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:197:\"In this episode, host Adam Weeks discusses cybersecurity strategies with Andrew Killen, Aaron Campbell, and Mart Virkus, exploring the collaboration essential for addressing evolving cyber threats.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 01 Apr 2026 09:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:45;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:99:\"Open Channels FM: Latest Jetpack Social Updates and the Return of X Integration for WordPress Users\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551633\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:106:\"https://openchannels.fm/latest-jetpack-social-updates-and-the-return-of-x-integration-for-wordpress-users/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:208:\"In this episode, Derek Hanson chats with Devin Walker about Jetpack Social updates, including interface redesign, Twitter integration, AI features, and upcoming WordPress 7.0 enhancements for WordPress users.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 31 Mar 2026 11:33:34 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:46;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"Open Channels FM: TestAlly for Developers\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551572\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://openchannels.fm/testally-for-developers/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:157:\"The Hackathon team discusses their AI tool, TestAlly, focusing on improving accessibility for developers while enhancing collaboration and business benefits.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 30 Mar 2026 12:14:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:47;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"Open Channels FM: The Case for Connecting Decentralized Networks\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551253\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://openchannels.fm/the-case-for-connecting-decentralized-networks/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:200:\"The discussion emphasizes the complexity of creating a universal decentralized social network, highlighting the importance of innovation, competition, and building bridges between differing protocols.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 30 Mar 2026 07:47:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:48;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"Matt: JAŸ-Z Returns\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151726\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"https://ma.tt/2026/03/hov/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:851:\"<p class=\"wp-block-paragraph\">Since <a href=\"https://www.nytimes.com/interactive/2017/11/29/t-magazine/jay-z-dean-baquet-interview.html\">he spoke to Dean Baquet in 2017</a>, JAŸ-Z hasn&#8217;t done an interview. Hov&#8217;s back! <a href=\"https://www.gq.com/story/jay-z-cover-interview-april-2026\">He sat down with GQ</a>, and it&#8217;s a lovely listen and read. </p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">We played enough defense, 2026 is all about offense.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Your morality defines who you are, not what you’ve attained.</p>\n</blockquote>\n\n\n\n<figure class=\"wp-block-embed alignwide is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 30 Mar 2026 00:44:41 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:49;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:99:\"Gutenberg Times: Gutenberg Changelog #129 Artificial Intelligence, WordPress 7.0 and Gutenberg 22.8\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://gutenbergtimes.com/?post_type=podcast&p=45087\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://gutenbergtimes.com/podcast/gutenberg-changelog-129/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:66144:\"<p class=\"wp-block-paragraph\">In this episode, Birgit Pauli-Haack welcomes Beth Soderberg to discuss key updates in WordPress 7.0 and Gutenberg 22.8. They kick off with small talk about shifting seasons in Munich and Virginia before diving into the new content guidelines in Gutenberg 22.7, focused on standardizing editorial voice across AI and human content contributors. Both speakers express healthy skepticism about AI-generated content, stressing that while AI assists with research and “grunt work” like alt text or excerpts, the core value in writing remains human expertise and review. They caution about automation pitfalls and emphasize validating all AI outputs.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The discussion shifts to the new WordPress AI connectors, which let users connect to services like OpenAI, Gemini, Anthropic Claude, and others—including local providers such as Olama and European alternatives like Mistral. Birgit Pauli-Haack explains the evolving infrastructure allowing developers to add and switch connectors with ease, and encourages the community to experiment and test.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A central topic is the release of WordPress 7.0, with a highlight on the increased minimum PHP requirement to 7.4, likely to disrupt agencies with older sites. The admin’s new look-and-feel is poised to confuse some clients, demanding extra support from agencies. Beth Soderberg also celebrates practical improvements: cover block video embeds using external sources, block visibility by screen size, pattern overrides, breadcrumbs block, and streamlined font management. Both speakers note the importance of hidden, friction-reducing features and the advancement of developer-facing infrastructure. The episode closes with a preview of ongoing enhancements in Gutenberg 22.8 and beyond.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-129/#shownotes\">Show Notes</a> / <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-129/#transcript\">Transcript</a></p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Editor: <a href=\"https://www.linkedin.com/in/sandy-reed/\">Sandy Reed</a></li>\n\n\n\n<li>Logo: <a href=\"https://markuraine.com/\">Mark Uraine</a></li>\n\n\n\n<li>Production: <a href=\"https://icodeforapurpose.com\">Birgit Pauli-Haack</a></li>\n</ul>\n\n\n\n<p class=\"has-larger-font-size wp-block-paragraph\" id=\"shownotes\"><strong>Show Notes</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Special Guest: Beth Soderberg</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://bethink.studio/\">Bethink Studio</a></li>\n\n\n\n<li><a href=\"https://profiles.wordpress.org/bethsoderberg/\">WordPress.org Profile + Slack</a></li>\n\n\n\n<li><strong>Talks by Beth Soderberg</strong>\n<ul class=\"wp-block-list\">\n<li><a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-122-gutenberg-21-8-and-wordpress-6-9/\">Gutenberg Changelog #122 – Gutenberg 21.8 and WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://wordpress.tv/2025/07/25/my-process-for-building-a-custom-wordpress-theme-in-2025/\">My Process for Building a Custom WordPress Theme in 2025</a></li>\n\n\n\n<li><a href=\"https://wordpress.tv/2020/04/16/bill-ericksonellen-bauer-beth-soderberg-case-studies-how-to-prepare-your-theme-for-gutenberg/\">Bill Erickson,Ellen Bauer, Beth Soderberg: Case Studies – How to Prepare your Theme for Gutenberg</a></li>\n\n\n\n<li><a href=\"https://wordpress.tv/?s=beth%20soderberg&amp;sort=newest\">And more</a></li>\n</ul>\n</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">AI in WordPress</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/ai/2026/03/23/guidelines-lands-in-gutenberg-22-7/\">Guidelines Lands in Gutenberg 22.7</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/ai/2026/03/25/call-for-testing-community-ai-connector-plugins/\">Call for Testing: Community AI Connector Plugins</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/plugins/ai-provider-for-openrouter/\">AI Provider for OpenRouter</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/plugins/ai-provider-for-ollama/\">AI Provider for Ollama</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/plugins/ai-provider-for-mistral/\">AI Provider for Mistral</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/plugins/ai/\">AI Experiements plugin</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>WordPress Core and Gutenberg</strong></p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2026/03/25/wordpress-6-9-2-retrospective/\">WordPress 6.9.2 retrospective</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/news/2026/03/wordpress-7-0-release-candidate-2/\">WordPress 7.0 RC2</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/25/whats-new-in-gutenberg-22-8-25-march/\">What’s new in Gutenberg 22.8? (25 March)</a></li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Dev Notes</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2026/03/16/pattern-overrides-in-wp-7-0-support-for-custom-blocks/\">Pattern Overrides in WP 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/15/pattern-editing-in-wordpress-7-0/\">Pattern Editing in WordPress 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/15/block-visibility-in-wordpress-7-0/\">Block Visibility in WordPress 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/15/dimensions-support-enhancements-in-wordpress-7-0/\">Dimensions Support Enhancements in WordPress 7.0</a> </li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/15/custom-css-for-individual-block-instances-in-wordpress-7-0/\">Custom CSS for Individual Block Instances</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/15/new-block-support-text-indent-textindent/\">New Block Support: Text Indent (textIndent)</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/18/introducing-the-connectors-api-in-wordpress-7-0/\">Introducing the Connectors API in WordPress 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/24/introducing-the-ai-client-in-wordpress-7-0/\">Introducing the AI Client in WordPress 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/24/client-side-abilities-api-in-wordpress-7-0/\">Client-Side Abilities API in WordPress 7.0</a></li>\n</ul>\n\n\n\n<p class=\"has-large-font-size wp-block-paragraph\">Stay in Touch</p>\n\n\n\n<div class=\"wp-block-group\"><div class=\"wp-block-group__inner-container is-layout-flow wp-block-group-is-layout-flow\">\n<ul class=\"wp-block-list\">\n<li>Did you like this episode? <a href=\"https://lovethepodcast.com/gutenbergchangelog\"><strong>Please write us a review </strong></a></li>\n\n\n\n<li>Ping us on X (formerly known as Twitter) or send DMs with questions. <a href=\"https://twitter.com/gutenbergtimes\">@gutenbergtimes </a>and <a href=\"https://twitter.com/bph\">@bph</a>.</li>\n\n\n\n<li><em>If you have questions or suggestions, or news you want us to include, send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a>. </em></li>\n\n\n\n<li><em>Please write us a review on iTunes! <a href=\"https://gutenbergtimes.com/itunes/\">(Click here to learn how)</a></em></li>\n</ul>\n</div></div>\n\n\n\n<p class=\"has-large-font-size wp-block-paragraph\" id=\"transcript\"><strong>Transcript</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Welcome to our 129th episode of the Gutenberg Changelog podcast. In today&#8217;s episode we will talk about WordPress 7.0 and Gutenberg 22.8. I&#8217;m your host, Birgit Pauli-Haack, curator of the Gutenberg Times and full-time core contributor for the WordPress open source project sponsored by Automattic. With me today, and I&#8217;m really happy about that, is again Beth Soderberg, founder and CEO of Bethink Studio, a full-service boutique agency and of web experts to tackle any project. Beth has been a longtime WordPress theme builder and WordCamp speaker. She&#8217;s also been an early adopter of the blog editor and block themes. Beth, how are you today? Welcome to the show.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I am well. How are you today? Thank you for having me.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>I&#8217;m good, I&#8217;m good. We have winter in Munich again. It was spring and now it&#8217;s back to winter. So I&#8217;m happy to get out of the town for WordCamp Asia next week. So yes, I&#8217;m really happy about that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>We&#8217;ve been switching from winter to spring every day here. Every day in Virginia. Yep. It&#8217;s different every day.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. So what&#8217;s the weather doing? Well, I don&#8217;t know.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>No, I&#8217;ve had to look every morning because it&#8217;s in the last week I&#8217;ve been outside in a winter coat and a tank top and rain boots and you just don&#8217;t know. You wake up and it&#8217;s a surprise.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Well, it&#8217;s the beauty of surprises. But who likes surprises? I want my spring be steady.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg:</em> Yeah, I agree.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Announcements</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>All right, so under the announcements we have one thing that&#8217;s that content guidelines landed in Gutenberg 22.7. We didn&#8217;t really talk about it with Maggie Cabrera at the last episode, but the WordPress AI team has launched guidelines. They are live experiments in the Gutenberg 22.7 or Gutenberg plugin and this project creates a single source of truth for site standards and ensures that everyone, humans and AI tools, follow the same editorial voice and content rules. By providing this infrastructure layer, WordPress can finally maintain a consistency across content contributors. So that&#8217;s so far from the experiment post that I&#8217;m definitely going to share in the show notes. When you want to use AI for helping you produce content, you definitely want to store some of the standards somewhere. And the experiment lets you do this on your website in your interface with a nice interface for that. I don&#8217;t know how I feel about this because I have been using AI quite a bit in the last two years and some of it was for content creation ideas. But the writing is still kind of mostly a human factor. But it helps me for research and it helps me for learning. So I&#8217;m not quite sure how that translates to a WordPress site, but I guess if you have ongoing content reproduction that is more service oriented, then you might want to use the help of LLMs or something like that. What do you think?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I&#8217;m skeptical for the same reasons. I think that I have had clients ask for something like this. But the more those clients have actually used AI to create content, the more those very same people who had announced that they were going to create all of their content through AI decide that they are going to use AI for research and then create their content. So the AI in actual practical use has been more about reducing friction in that discovery research phase of writing and less about creating the writing itself until you get to the editing part when it becomes helpful again for grammar. But that actual connecting ideas and proving expertise piece is where AI can&#8217;t do it. And you need something, somebody who actually understands what they&#8217;re reading to piece together the logic of it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>I can also see, and we will see this in that you use AI to write an excerpt or to give you suggestions for titles or make sure that there&#8217;s an alt text on the image. I think these grunt work tasks kind of thing of AI is really helpful, but I think the human ideas are still. Well, humans hallucinate so much better than AI can ever can. Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>How can we possibly replicate that? And I think there&#8217;s also a place for it with things like you mentioned the alt text. Right. Having it generate them all and then validating that it did it correctly is much faster than writing it all yourself. That is where we&#8217;re going to see these things actually become practical. Right. There&#8217;s a lot of big ideas about it, which makes sense when you&#8217;re dealing with a new technology and an innovation in a major workflow. But in actuality, I think that&#8217;s more how people are going to use it. And I think if people set it up to automate everything and then never look at it, never validate it, that&#8217;s people are just going to get in trouble over that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And I, you know, I use it a lot to generate fake content so that I can show someone what something will look like knowing that the content I&#8217;m showing them is not real. Right. But when you&#8217;re dealing with real content, the biggest mistake I&#8217;ve seen over and over again, and humans will learn because we always eventually do. But the mistake is not reviewing what AI has done.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, definitely. Yeah. It&#8217;s not a replacement. It&#8217;s a tool that you need to validate like any other tool you have to do. I can see that if you have a longer text like for 4,000 words or something like that, you could actually use AI to identify the gaps. If a reader goes through it and say, okay, there is a gap because it didn&#8217;t explain why something happens. I think those tips are really helpful, especially when you have longer text or you want to focus on one problem and just kind of figure out what&#8217;s in scope and out scope. But I think that&#8217;s more like an advisory kind of thing and not a doer.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, validating. Because sometimes I love Grammarly Pro. Grammarly the free version is very annoying, but if you pay it becomes a really useful tool. But even then, the content suggestions it makes, sometimes they tighten up your language and they make it. They add the commas, which is the thing that I don&#8217;t do naturally on my own apparently. But sometimes they change the meaning completely.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And that&#8217;s when you&#8217;re like, nope, thanks for the suggestion. That&#8217;s a no.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I think how this type of thing used well, will make people more efficient. But I also can see it creating a mountain of work for somebody who doesn&#8217;t actually need to go through all of these ridiculous suggestions about it. And I think that deciding when to use it, when it makes sense, those strategic decisions about how to use it are going to be what makes it either something that really helps somebody in their publishing workflow or really hinders somebody else.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Well, if you&#8217;re a single blog blogger having a little editor go through that and give you some tips that might not be a bad idea, but sometimes. But right. If you have been blogging for many, many years, you don&#8217;t need things like that. It changes your voice and it changes the outlook. That&#8217;s what the guidelines are actually for that you can create some of the guidelines as it meant to be to help AI to streamline some of that stuff and also to know about what you want to do. And that certainly helps.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, yeah.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Community Contributions</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Speaking of AI, what I found in so in 7.0 WordPress. So getting closer to that release, there is now a new connectors page that you could connect to an OpenAI to Google Gemini or to Anthropic Cloud from your site. And if you have certain tools that help you with those connections. So there are AI providers for other AI systems like I just discovered three of them. One is the AI provider for Open router or router depending on which English speaking country you go to. It&#8217;s a little bit different. So open, I say Router is a service that lets developers use many different AI models like those from Google OpenAI but also others through one simple connection. And the provider was developed by Jonathan Bossenger who is on the AI team and talks about AI on the developer blog. There&#8217;s also an AI provider for Ollama, and Ollama is a local system where you can connect local LLMs so you can download an LLM set and Ollama helps you connect that with the task that you want to do. The benefit of Ollama is that it&#8217;s on your server and it doesn&#8217;t go out to the third-party services, but you still need a provider and connector to it. You can do this on any VPS connection or virtual private server system because you have room and space there to download and add certain things. But it&#8217;s definitely important for companies that want to not get data outside of their system. </p>\n\n\n\n<p class=\"wp-block-paragraph\">And the last one is for Europeans. The AI provider for Mistral. Mistral AI is a French AI company founded in 2023 by a former Google DeepMind and Meta researchers and they built and publish large language model and be a respected independent AI in Europe. Speaking of this, what that all comes together is that the AI team and with that Lauri Saarni published a call for testing for community AI connector plugins. There are certain links to the plugins and the connectors, so it would be really cool if you&#8217;re interested in that part of it, to actually go ahead and test things and report back what you find and what you didn&#8217;t find and how it all works for your site. It&#8217;s a totally different approach for working with the site using AI as we discussed. But it might be pretty interesting for developers to connect with all those AI providers and provide services in a plugin or something like that. </p>\n\n\n\n<p class=\"wp-block-paragraph\">And if you are not a developer, you can install the AI Experiments plugin that also comes from the core AI team and it will show up on the Connectors page with a link to the plugin and what you can do with it. And it has these things like create an excerpt or check the alt text or create a featured image just so you can kind of get a feel for these kinds of works on the WebPress site. Do you have, do you think you have a need for. To kind of use some of the providers for your agency or for some clients?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I think for some clients it has started. I think that for the agency itself, not yet. We have started to do more writing publicly, but really what we&#8217;re doing is turning internal communications to clients into public facing documentation so that we can point to them more easily. So it&#8217;s not something we need help with. In the same way, I think for some clients we have started to integrate things like this in an experimental way. Right. And there are, as with anything that&#8217;s new, people don&#8217;t know how to use these things yet. And I am not against experimenting with a new thing. I love the new stuff, but at the same time I&#8217;m cautious about putting new things into a production environment without really making sure that it makes sense. Some of these, in terms of experimentation, like I will install them and actually Grammarly is a great example. It took me several years to decide that I was fine with it because I tried it and it was annoying. And then a few years later I tried it again and it was still annoying. And then one day I realized that it really was like their premium suggestions really were fixing my comma issue, which is a known issue I have with writing and grammar. I just don&#8217;t put commas anywhere.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>I put them in randomly and so there&#8217;s a few commas.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>But you know, I experimented with the tool probably three times before I was like, you know what, let me try the premium version and see how that goes. And I tried it and a few days later I was like, yeah, this is actually making my writing better. But it was one of those, like I was monitoring over time if it really made sense with my workflow.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, yeah. And that&#8217;s how I approach it too.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, yeah, yeah. That&#8217;s how I felt about these. And I think what&#8217;s exciting about it is that the infrastructure to do it is becoming more full fledged. But that does not mean people know how to do it yet.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack:</em> Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And so that&#8217;s the next step is that experimentation phase collectively of how, what. How can we make these tools that we&#8217;ve now created function in the best way.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>So I really appreciate that the WordPress core developers think about the plumbing of all these services and putting it all the foundation in to open up that total space for freedom for the developers. And there&#8217;s a standard there on how to approach certain. So if you are as a site owner, don&#8217;t have a plugin that kind of taps into LMMs and you open up Gemini for it, you couldn&#8217;t switch just easily to Claude when you think that&#8217;s a better fit for that problem, but the plugin will still work. So that&#8217;s actually what this whole connector thing is about. And it just came up as for the AI providers, but actually the connector API is for any external service standard. So a standard for any external service. So if you need the OpenStreetMap on your site and you have an API key, the plugin can actually use the connectors API to monitor those API keys and just put it in there. The plugin doesn&#8217;t have to come up with its own interface for that, which a lot of plugin developers did for the last 15 years. Yeah. But now they can could actually throw away that piece of the plugin and just tab into the connectors API and don&#8217;t have to maintain that piece of the code.</p>\n\n\n\n<h3 class=\"wp-block-heading\">What’s Released &#8211; WordPress 7.0 RC2</h3>\n\n\n\n<p class=\"wp-block-paragraph\"> But anyway, so that&#8217;s kind of the bigger picture behind it. And that&#8217;s all coming with WordPress 7.0, which we are now getting to the more practical stuff of WordPress 7.0. So first of all, the WordPress 7.0 release candidate 2 has been published this week. It&#8217;s crunch time. The final release is only two weeks away. So if you haven&#8217;t tested it, now is really the time to get in there and figure out if your theme plugins and sites actually still work with 7.0, and the developer notes are published. The field guide is in the works and I will continue the list of dev notes in the show Notes like we did the last two episodes. I also know because I have been working on it. The Gutenberg Times Source of Truth is almost done and will be published before this episode actually hits your favorite podcast app. So you get an additional link there. So, Beth, did you get a chance to look over the WordPress 7.0 features? What are the most important ones for you and your fellow agency owners and developers? Is there anything that you are really excited about?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yes and yes. So the first thing that I think is going to be honestly hugely problematic for a lot of agencies is the change in PHP minimums, because I think that there are. I know that there are a lot of folks sitting on older sites, older themes, maybe they&#8217;re stuck at PHP 7.1 and there are old things out there. And I think that this PHP requirement jump is going to catch some people off guard. So it jumps from it&#8217;s we&#8217;re now requiring 7.4.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And if you do, it&#8217;s already 6.9.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Right?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah. But I think this is going to hit harder. Okay. Because people are going to want the new stuff. Like there&#8217;s a lot in here that is really great and I&#8217;m starting with the thing that I think is going to be most disruptive because I think that people are going to want the other stuff, right? And so I think that that&#8217;s going to catch some people off guard. The other thing that I think is going to be really important is the new admin look and feel because people have been training their clients for many, many, many, many, many years with what it looks like now. And there is a client education need here because when the admin changes, even in minor ways, you get clients that come back and say, what happened? I don&#8217;t know how to do it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Okay, Even if nothing changes except the color, right?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Where did it go? Why is this different? And did I do something? Did I write the, that human element of like, hey, you&#8217;re okay, it&#8217;s gonna look a little different, but I promise you&#8217;re gonna be able to do it. Just holler if you have any questions. Right? Because I think that there&#8217;s a lot of at least working with long term clients where you become sort of an advisor on the technology rather than a day to day implementer. And for those folks with something like this, I, what I like to do is say, hey, heads up, we are doing, we never do the major core updates right away. I am a let me see how it goes for everyone else.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Type and then if it seems okay, then I&#8217;ll go for it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack:</em> So you&#8217;re one of the ones who wait for 7.0.1.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Absolutely. Unless it&#8217;s been like three weeks and there isn&#8217;t one. Yeah, right. So I either wait for a period of time or I wait for a point release. And if there&#8217;s a point release, I wait at least 24 hours to make sure there&#8217;s not another point release. But point being though, that this is a big enough shift in terms of what people will see and what people can do.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Which part of the admin is actually the one that will disrupt people&#8217;s minds.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Just I think it looking different at all.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Oh, okay. So we should never change that. Is that what you&#8217;re kind of thinking?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>No, we should absolutely change it. But because we have not changed it for many, many, many years, it will be a surprise. And I think that it&#8217;s easy as folks who are in these systems every day to be like, wow, they finally fixed that. That&#8217;s great. That might be my reaction to many of these changes. Right. But I also know when I log in to pay my credit card. And they&#8217;ve changed it all. And even though the buttons are the same, it looks different. I don&#8217;t have as much confidence about clicking the button. And there&#8217;s this. The vast majority of people who are maintaining the contents on these sites day to day are marketing people, communications people, regular everyday writing people. And they are not sitting there thinking about how the structure of the software works all the time the way we do.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. But they still get their work done.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>They still get their work done. What I like to do with clients is just reduce friction by increasing confidence.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Right. And so, like, my message to them is going to be, hey, you need to know that this is going to look different, but your workflow in terms of the things you know how to do is the same. Don&#8217;t let it freak you out. You&#8217;ve got this. Keep going. Right. But like, just that little bit, because that&#8217;s. That is 100% what gets people. It&#8217;s the smallest stuff. They just need to know, like, hey, the problem&#8217;s not me. Oh, wait, there&#8217;s not a problem. It&#8217;s fine. And then they&#8217;re good.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. Yeah. It&#8217;s the first five seconds. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>It&#8217;s that psychological adjustment. And I think because it hasn&#8217;t changed for so long that it&#8217;s just going to be something that I mentioned.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Is there anything else that you are really excited about or is it just.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I know. Okay.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Things change. Okay. I don&#8217;t like it to change.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Things change. I&#8217;m really, really excited about the cover block video embeds.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>That is really, really going to reduce the size of things as they load for a lot of websites. And that is fabulous. In addition to improving workflow, all of the things around block visibility by screen size make me really happy. I&#8217;m really happy about the changes in the header block. And I&#8217;ve been building this into themes for years. And the only thing that makes me nervous about it is that I need to go back and see how it impacts the things I&#8217;ve already built that replicate this feature.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>But you mean the navigation overlays?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>The navigation overlays. Yeah. Because you&#8217;re going to have such increases in both accessibility compliance and SEO optimization just by virtue of having the option to manage your headings visually versus syntactically. So I&#8217;m very excited about that. I love that our revisions menu now has visual changes.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack:</em> Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Because I know that most people looking at the markup that&#8217;s been in there lately are like, I don&#8217;t know.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. I have to squint so much to look through the code to find things. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And then there&#8217;s a few exciting changes to the navigation and the better workflows for pattern overrides. Yeah, it was there before, but it was one of those mystery off menu features if it was there, if you knew how to find it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, yeah. Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>So those are the things I&#8217;m most excited about. I think there&#8217;s some other cool stuff in there and I am excited about the general infrastructure that we were just referencing that is being solidified with this release. And I think that piece may not be as exciting on the outset because it&#8217;s infrastructure. It&#8217;s like nonprofits have a hard time funding infrastructure process projects. It&#8217;s the same reason. But it lays the groundwork for a whole new level of experimentation. I&#8217;m excited to see where that goes and I recognize I think you said it very well a few minutes ago the thoughtfulness to create an extensible infrastructure that has gone into these features in the roadmap and sort of planning moving forward.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>You mentioned the cover block video embeds. That means that you can have a video just to catch up with our listeners. It&#8217;s to use a URL to YouTube or to Vimeo and pull that in into a cover block instead of uploading the video to the website because that reduces the cost of hosting and bandwidth for the website. Definitely. And it also you don&#8217;t have to maintain the speed and all that on your own server. So it&#8217;s always good to offset that into a different service. How are you feeling about the manage the fonts from the appearance menu directly instead of hunting it down under the fonts typography menu on the slobber styles,</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg:</em> I&#8217;m feeling really good about that. It remains to be seen for me the biggest issue I have with font management. I am not sure it might be addressed here, but I need to experiment. When you get a font from a total third party non-standard like independent type foundry place getting those integrated, there has still been some friction. So I&#8217;m excited about it being easier to find in general. I think that&#8217;s great. .</p>\n\n\n\n<p class=\"wp-block-paragraph\">I will be experimenting a little bit with if it reduces friction in some of these more edge cases. Because if you&#8217;re using a Google font it&#8217;s great and it&#8217;s been pretty good for a while. But if you are integrating something from another provider, if it&#8217;s a big provider the friction is not as bad. But if it&#8217;s like this obscure type foundry that makes like only these little types of historic fonts, which I run into recently, getting it actually integrated properly, it&#8217;s really hard because you&#8217;re dealing with not the most sophisticated type foundry in terms of the format of their files and they&#8217;re not necessarily plugging in as best as the totally optimized stuff from the more common sources. So, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Is it more a format issue or is it more kind of how it scales in different font sizes and different typography features?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>It&#8217;s a format issue with the font files themselves. And so I think some of it is probably an education piece for people who make fonts, but I also know that most developers don&#8217;t know that much about how fonts are made. And so when you put those two things together, you create some problems. But I think this is a huge step towards getting to the point of being able to solve the edge cases. Right. Because right now finding where you manage the fonts is difficult.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Right? Yeah, totally. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>We&#8217;re going in a great direction, getting into the nitty gritty of which font providers are supported and that I think that&#8217;s the next step from here, personally, because I do think there&#8217;s a homogeny that started from a type standpoint around everyone&#8217;s using Google fonts because they. It&#8217;s easy.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. But it&#8217;s also problematic for European sites.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, right, yeah. Because the different requirements over whether you&#8217;re hosting the font files or Google is hosting the font files, like, then you&#8217;re getting all into all of these legal technicalities of where the font is and who owns it. And I&#8217;m glad I&#8217;m not a lawyer.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, me too. So, all right, so there are a few developer goodies coming, so to speak, down the pipeline. The PHP-only block registrations and then the pattern overrides for custom blocks that you already mentioned. Those. I think there are a few smaller stuff like the HTML block enhancements where you can put the CSS separately from the JavaScript and the HTML. You could actually kind of create your own little app there, depending on what privileges you have. I found that there are some problems when you don&#8217;t have admin privileges. The HTML block really gets scrambled, but that&#8217;s an overall kind of problem with the capabilities, I think. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Oh, I forgot the breadcrumbs block. That. That&#8217;ll help a lot of things.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>So. Yeah, yeah. I&#8217;m also sure that a lot of agencies and site owners already had that problem solved through like for instance, the Yoast SEO plugin had already programs for many, many years. Yeah, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>But I like my websites to be as lean and efficient as possible. And this feels like when, for a long time I was using Coblox for accordions. Right. And in the beginning, coblox had a lot of things that Core didn&#8217;t. And so you were using a bunch of things. And eventually it became that I was only using the accordion everywhere. And then one day it became possible to do the equivalent in Core and I was like, great, I can get rid of this plugin that&#8217;s only doing this one thing, but has all this other stuff. And I think that&#8217;s what makes me excited about this. Yeah. You can do it through Yoast. There&#8217;s a number of ways to do it. There&#8217;s some independent breadcrumbs block plugins that are really good.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. I know that Justin Tadlock had a very good breadcrumbs plugin and he was advising on the core implementation there.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, right. Yeah. And I&#8217;ve used Justin Tadlock&#8217;s breadcrumbs plugin for a long time, and I&#8217;m not going to rip it out of something just because it&#8217;s there. It works. It&#8217;s good. But for something else where, like, you only have this one thing that you&#8217;re really using in this big suite of plugins. Yoast is one of them. Jetpack is one of them. Any sort of like cadence blocks, code blocks, any collection of a large number of things when you&#8217;re only using one of them, you should be considering the idea that maybe you shouldn&#8217;t use it at all. And that&#8217;s what makes me excited about the ability to do this through Core, because it allows for some of that extra bloat to be stripped away in some circumstances.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. All right. Anything else that you want to kind of cover on 7.0 for your agency of developing theme building needs?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I think that the PHP-only block registration, we sort of glanced over it, but I think that&#8217;s a very exciting big deal. It opens up, you know, the whole challenge. I think from a developer standpoint, the whole time with Gutenberg has been, how do I level up to do this new thing? How do I level up to do this new thing? And this opens that door wider. And anything that we are doing to open that door wider is great. Similarly, there&#8217;s a few things in here that are just really tiny that I think will help people. They&#8217;re not like, again, reducing friction. So little enhancements to the query loop, adding some new navigation stuff that is just really tiny, but really Helpful dimension support for width and height. That sounds crazy, right? Like it&#8217;s little tiny stuff that reduces friction and stuff. So there&#8217;s more of that in here. Like the concept of the grid block being responsive is really great.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Well, it was responsive before, but there was a setting where it wasn&#8217;t and that&#8217;s kind of changed now, right? Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>So, yeah, I just. There&#8217;s a lot of hidden goodies in here that reduce friction. I do think the biggest things to look out for are if your themes are compatible, if your plugins are compatible, and if you have built in things that replicate some of this functionality. How does that work? Because we&#8217;re starting to enter, at least for how I&#8217;ve been building themes, a zone where things I have done historically to account for some of these needs are being subsumed by core, which is great. I just don&#8217;t know how it&#8217;s going to work. So, you know, I think that&#8217;s going to be different for everyone in terms of which things it is. But hopefully, and I say hopefully because I know that we have a unified development philosophy about how we build our themes and there&#8217;s sort of a continuous logical thread for our themes as they&#8217;re built over time. Hopefully agencies who have an internal logic to how they have been building themes can look at this list and say we should look at how we do that and make sure it still works. Yeah, right. Because there&#8217;s also going to be agencies where they have a mishmash of things and they don&#8217;t know and it&#8217;s going to be a one off for each site to see what happens. And you know, that goes for anybody who&#8217;s inherited themes too.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, but that&#8217;s also for any of the WordPress releases. Yeah, you have to go through a certain testing phase there.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, I think that&#8217;s true. And I think some of this is honestly that it&#8217;s been a while since we&#8217;ve had a major release and so the quantity of little things feels more.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, absolutely.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And I think that&#8217;s part of why my reaction is this way, because I haven&#8217;t had this thought process.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>At least five months.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>At least.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, six months. Nine came out December 2nd.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Right. And so as somebody who was used to the four times a year cadence, it is longer and what&#8217;s packed into it is greater. And so I don&#8217;t think that&#8217;s necessarily bad, but it is an adjustment in terms of absolutely how you review things and what you&#8217;re looking for. And it&#8217;s more of a. This one feels more like a surprise. Not that it is a surprise, but it feels more like a surprise because it is not on this schedule that I had come to expect. Right. And I think we&#8217;re getting towards a new schedule, which is really great. But until we are all psychologically adjusted to whatever that new schedule is, it&#8217;s going to be a slightly bigger task to review because there&#8217;s more. And psychologically it&#8217;s going to be like, oh, right, I guess that&#8217;s happening and you&#8217;re, you know, you got to go do it. Yeah. So I just think it&#8217;s just. There&#8217;s a little more and the timing is not as predictable.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. And I think that the break that was in Twenty Twenty-Five kind of skewed that anyway. Yeah. So we had an April 25, we had a release, and then the last. The next one wasn&#8217;t until December. Yeah. So there were eight months that kind of 15 Gutenberg plugin releases. It didn&#8217;t feel that much that it is now in 7.0, because that was just kind of coming up out of that pause. And now there&#8217;s a real excitement about the Real Time collaboration. There&#8217;s excitement about AI. Yeah. So, yeah, it feels that there are quite a few heavy new features in there that also kind of drown out some of the really quality of life things that we have been waiting for quite a bit here.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Right. Yeah. And I. I think it&#8217;s like coming back from a long vacation, like, oh, ooh, this is really exciting, you know, but that&#8217;s how. That&#8217;s how it feels and it&#8217;s good. But it is, absolutely. I think that Twenty Twenty-Five, you didn&#8217;t have to be as vigilant because it wasn&#8217;t happening.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yep, it was a good break.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I think everyone needed it. Honestly, I think everyone really needed it. I know I needed it. But it is, you know, getting back into the. The groove of things is. Is where we are now.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>So. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>For which I am thankful, but it&#8217;s still an adjustment.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Me too. Yeah. And now with 7.0 kind of out the door almost. Yeah. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Gutenberg 22.8</h3>\n\n\n\n<p class=\"wp-block-paragraph\">We are looking at Gutenberg 22.8 that has been released. Was released this week also kind of what comes into 7.1. It&#8217;s already starting and people are discussing things. So although there were quite a few PRs that were either all part of the new WordPress UI package that hasn&#8217;t been merged into Core yet, or it&#8217;s bug fixes for the connectors or the Real time collaboration for 7.0, so some of the PRs are actually backported to the release candidates and the beta to the release candidates. </p>\n\n\n\n<p class=\"wp-block-paragraph\">But let&#8217;s talk about some of the things that will not be in 7.0, but definitely in 7.1 and what&#8217;s new in the Gutenberg plugin. So the first thing is the navigation support for the current menu item. So in theme JSON, meaning when you have a navigation and you&#8217;re on a current page that&#8217;s part of the navigation, how do you signal that you are at the current page right now in the navigation? And that has been missing for quite a while or people have just did some CSS workaround of that, but now you can actually style that in theme JSON. And so this is cool. What&#8217;s also cool is that there is an interface for the states like Hover Focus current. I&#8217;m not sure if that&#8217;s going to be in there, but it&#8217;s also part of making the navigation and the hover states and the pseudo support that comes into 7.0, but now it comes also to the interface. So that&#8217;s pretty cool.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>That&#8217;s my favorite part.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Which one?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg:</em> The navigation stuff again. The interface around the navigation has gotten a lot better in various iterations of Gutenberg, but there&#8217;s still some stuff that you&#8217;d think you would be able to do that you can&#8217;t. And that&#8217;s what some of this is filling in.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Birgit Pauli-Haack: There have been some great work. Some of it gets into 7.0 and some of it is still ongoing. So I really like the navigation that&#8217;s actually in 7.0, that you can create pages and publish them and have them in the navigation in one workflow kind of thing. You don&#8217;t have to get out of it. You may have to think about it. You just kind of create the page and then you fill it in with content later.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah. And I&#8217;ve seen that in other systems. I don&#8217;t remember what that is. One of those things where some of these changes, you&#8217;re like, you know, I saw that once somewhere. Was it Joomla? Was it Drupal? Was it whatever? I don&#8217;t know. But I liked it. And now it&#8217;s here. And that&#8217;s good.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Absolutely.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And that&#8217;s how I feel about that because I do appreciate the tiny little decisions that are being considered here by the core team because it seems very small. But the amount of friction you&#8217;re reducing and the amount of time you&#8217;re saving for people is huge.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>It&#8217;s huge. Yeah. Yeah. And it&#8217;s millions of millions of site owners that kind of have advantage. Yeah. Do you want to take the next</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>thing, the tabs menu. So I think this is going to be fun too. So basically we&#8217;ve got a refactor of the tabs menu block. So it&#8217;s basically making this more efficient and making some templating changes to how the tabs block works. And if you look at the actual PR for it, there&#8217;s really good, very detailed descriptions of how. So it&#8217;s making it very clear of it&#8217;s no longer using the template block duplicated in PHP and instead it&#8217;s rendering with per tab context.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And that&#8217;s like all gobbledygook to some listeners. Maybe, but like really what it&#8217;s doing is making it more efficient and making it more extensible from a code perspective.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>And also for theme developers.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, right. And making it more possible again, opening that door a little wider for more people to be able to work within the code infrastructure. Because that has been the thing that&#8217;s been the biggest challenge in terms of developer adoption of Gutenberg.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. And the refactor was also necessary to bring it in line with the approach for the accordion block so that certain methods and certain functions can be replicated in a similar way for the TAPS block. I was actually sad to hear that very early that it won&#8217;t make it into 7.0, but I think that was one of the reasons where they said, okay, let&#8217;s, let&#8217;s see if we can kind of align it a little bit more with the accordion block. And it&#8217;s no surprise that Sarah Norris, who has been a guest here at the Changelog quite a bit, she also created the accordion block and she has been now instrumental on the restructure of the tabs menu and inner blocks to get it in line and we have make it more streamlined for developers and theme builders.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>The one thing to add that is an exciting piece for especially theme developers is the addition of anchor support for the tabs. So that&#8217;ll help a lot in terms of things like navigation structures and feasibility. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>And also to kind of interlink different pages. You can link to some of the tabs if it&#8217;s interesting enough. Yeah. So I know that WooCommerce is using that for their products template. So they have built their own one back then and now they get a little bit closer to core, which makes it more extensible and also appreciative they don&#8217;t have to maintain the code for it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yep, absolutely.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Which is quite a bit. So right now I&#8217;m fishing around on my computer to find my notes again. So here we are. All right,</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>the next one, the showing one&#8217;s own presence and collaborative editing sessions is I think existentially important and just is really going to help this UI experience from the baseline that&#8217;s being released in 7.0.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>So yeah, I&#8217;m pretty sure that it will actually come to 7.0. That made it into the release. That&#8217;s good. So the next piece is the one that you can have the site logo and icon screen in the design panel. So in the site editor there&#8217;s another menu item now to update the site logo and the icon screen directly from the site editor. So you don&#8217;t have to go out into the settings page and upload everything that you need or into the site logo block or header. You can do it right there from, from the menu. So it&#8217;s really an interesting update to change the site logo and the site icon directly in the design site editor.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>It&#8217;s reducing friction. I think that there&#8217;s a workflow confusion. There&#8217;s the customizer that has become this vestigial organ that sometimes you need, sometimes you don&#8217;t need. Where&#8217;s this? Wait a minute, where do I add css? Is it over here? Is it over here? Is it over here? Could it be here? And I think that we&#8217;re pruning what we need to do through alternate interfaces through changes like this. And the more we can streamline, the better because the biggest confusion I&#8217;ve seen is actually with brand new or like more junior developers who do not know the quote old way. And so the idea that it&#8217;s even there, like they&#8217;ll get stuck because they can&#8217;t figure out where it could possibly be coming from. And then some old timer is like, oh, it&#8217;s over here in this menu that you can&#8217;t see anymore.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. Or yeah. So the site icon at the site logo has been a hidden place and only until now it&#8217;s kind of coming into the forefront. Yes. So the next thing is another one for the collaboration. I just wanted to point out that by default the collaboration on shared hosting is only. It&#8217;s limited to two users and there is also a method for the hosts to either enable that or disable the real time collaboration. So it might not be as obvious when you go on your site and looking for it. You might not be able to get real time collaboration out of the box. You might need to connect with your host to let that enabled because it&#8217;s such an additional load on a server. That certain server configurations are not meant for it to be in yet. So if you&#8217;re on a virtual private host, I think I mentioned it before, it wouldn&#8217;t. It was a different scenario. But it&#8217;s probably easier to get the collaboration working than if you are on a shared hosting with 10,000 websites on a. On a server where the hosting company will probably restrict that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, I think that there&#8217;s going to be a lot of shifts in hosting, either requirements, configuration, pricing options, etc. as a result of all of these changes. And I don&#8217;t know what they&#8217;re going to be yet, but we do need to collectively remember that the AI features, the collaboration components, all of those things are resource intensive and are going to shift how hosting is being utilized and therefore the hosts are going to need to respond in order to account for the actual cost of that change. So I think that&#8217;s a big unknown right now and I think it&#8217;s, you know, there&#8217;s a few hosts where they&#8217;re locking in pricing for a few years, which is cool, but at the same time I&#8217;m like, I don&#8217;t know, in three years is this going to be enough to pay for that? What will it be in three years?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>So I think there&#8217;s a shift coming there and I am not gonna even pretend to know enough about all the details to know exactly how that&#8217;s going to play out, but I think that there&#8217;s enough shift in what types of resources we need from our hosting that there will be a shift. There has to be, because it&#8217;s just so much more resource intensive than what we&#8217;ve been doing in the past collectively.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack:</em> Yeah. And that is in line with what you said at the beginning, that the PHP requirements. Yeah, it always is also contributing to that because all the newer features. So there might be a. You can&#8217;t upload upgrade to 7.0 until you update your PHP. That&#8217;s totally sure.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah. And I&#8217;ve read that somewhere. Somewhere I did read that there&#8217;ll be security releases on 6.9 for sites that can&#8217;t go, you know. But then you end up with a situation where you&#8217;re gonna. How many sites are gonna be stuck on 6.9 forever?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>But that has been a problem. Yeah. Because the security team is actually backporting, although officially the release is only supported to 6.8 or something like that, but security team actually backported all the security updates that came with 6.3 or 6.4 to 4 point something. WordPress 4 point something is probably 15 years old. So it&#8217;s still getting security updates. So that definitely is a backwards compatibility promise that even the security team there. It takes a lot of time to backport that. And John Blackburn, one of the leads on the security team, has actually done a retrospective of the latest security updates because you saw that too. It was a. It&#8217;s kind of a galore of releases. 6.2, 6.3, 6.4, 7.4 beta. Yeah, it kind of was in within three days, I think there were four releases.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>It was a lot. Yes. All at once.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>I had a meetup here in Munich and we talked about it. I think the day the 6.4 came out that they were saying, well, is it all hacked or what happened here? Kind of how often do I have to update my WordPress site in a day? And he did a nice retrospective or explaining what happened and what was the reason for that. I&#8217;ll link it in the show notes if you&#8217;re interested. To listeners, it will probably be a little bit less prominent because of all the death notes that came out, but it&#8217;s on the blog on Core.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I&#8217;m going to go back and listen to that because that hit during a particularly busy time, just for me personally in general. And so it was a little whiplashy to be like what is going on over there? And I think it will be good to be able to go back and just review so that I am aware moving forward of what exactly happened there.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. And back to Gutenberg 22.8. I mentioned it before. There is a feature that implements the state UI for sudo selectors in the global styles. Maggie Cabrera mentioned that in the last episode. It&#8217;s now available in the Gutenberg plugin so you can test it out. It gives you a. In the global styles on the right hand side you can select the design for your pseudo selectors like hover and focus and all that. It&#8217;s really cool. Hover, focus, Focus, visible and active. Yeah, so you can change all those settings for buttons, for instance. And you don&#8217;t have to use theme JSON for it anymore. So this is pretty cool.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yes. And then this one, I think this is fascinating. There is a PR adding client side navigation block with interactive features. That just sounds really fun to experiment with. So what it&#8217;s doing is adding a variant to the Create Block interactive template that allows you to add client side navigation. So this is starting to support the again supporting the infrastructure that exists with actual tooling and UI to use it. So the way that it describes it, this variant provides a self contained working example that mirrors real world patterns, query parameter navigation for pagination, search results, filtered archives and works immediately after scaffolding with no posts or setup required. That&#8217;s really cool. That&#8217;s a really nerdy and very arcane and wonderful. So I&#8217;m excited about that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. And that variant is for the Create block scaffolding feature, if I understood this correctly. Yeah, it&#8217;s a create block latest. So if you create a custom block, you can have the variant for your client side navigation and scaffold that up. That&#8217;s really cool. Yeah. Well, our developer advocacy team, we are working on a so-called showcase for all the good things that you could do with a website or theme, including some of the interactivity API features. And we will probably release that someday in the next two months I would think. And it will be a music site with albums and musicians and artists and using the tabs and using the playlist and block and then also kind of have some interesting changes in the theme. So it&#8217;s for custom post types and all that. So it&#8217;s going to be really cool. I know that Juan Ma Garrido who put the client side navigation template into the gray block scaffolding, he&#8217;s also creating a plugin to have the music play even if you navigate away from that page that had the list of the music. So it&#8217;s kind of really interesting to see. So you could use it for video and music. So things stay on the forefront on your browser even if you look at other pages on the website. So that&#8217;s one of the features.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>The person, the, the part of me that likes to listen to podcasts from the website themselves really appreciates this.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. So I, I definitely, once it&#8217;s out, I definitely gonna adopt it for the good changelog podcast.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>So I think always through, we are through with booked. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg:</em> Lots of little, little things, but those are the big exciting things, I think.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. And there were actually 38 PRs that were backported as bug fixes to 7.0. So it&#8217;s still an ongoing work that is coming out in two weeks and people are still fixing it. </p>\n\n\n\n<p class=\"wp-block-paragraph\">All right, well, I wish you and your agency all the best for that release that all the things that come in don&#8217;t disrupt your work or the work of your clients.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>We have a list. We know where to look for the problem.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Excellent. Yeah. Well, I&#8217;m so happy that you were on the show with me. And as always, dear listeners, the show notes will be published on GutenbergTimes.com podcast this is episode 129 and if you have questions and suggestions or news you want us to include, send them to <a href=\"http://changelogutenbergtimes.com\">changelogutenbergtimes.com</a> that&#8217;s <a href=\"http://changelogutenbergtimes.com\">changelogutenbergtimes.com</a> so thank you for listening and I wish you all a great weekend. Well, or next week. And also toy, toy for the WordPress 7.0 release updates. We will hear each other again in four weeks once I get back from WordCamp Asia. And then we&#8217;ll tackle what&#8217;s coming in 7.1 and what has been in. Good work. Plugin 22.9 and 23.0. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Thank you so much. Beth Soderberg, it was wonderful to have you and your perspective and your opinions on the show.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Thank you for having me. It was great to be here and to see you again and I wish you safe travels on all of your continuing travels.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Thank you. All right. Yeah, and you take care. And I&#8217;ll put in the show notes how people can connect with you.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Sounds good.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Of course. All right, you take care. Bye Bye.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Bye bye. Thanks, everybody.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 29 Mar 2026 08:59:05 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";a:9:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Fri, 24 Apr 2026 14:46:59 GMT\";s:12:\"content-type\";s:8:\"text/xml\";s:13:\"last-modified\";s:29:\"Fri, 24 Apr 2026 14:30:23 GMT\";s:4:\"vary\";s:15:\"Accept-Encoding\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:2:\"br\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 2\";}s:5:\"build\";i:1760643936;s:21:\"cache_expiration_time\";i:1777085220;s:23:\"__cache_expiration_time\";i:1777085220;}','off'),
