\"fontWeight\":\"700\",\"textColorClass\":\"has-palette-color-1-color\",\"textColor1\":\"var(\\u002d\\u002dtheme-palette-color-1, #145AE2)\",\"fontSize\":\"18\",\"contentAlignTablet\":\"center\"} -->\n<div class=\"wp-block-stackable-text stk-block-text stk-block stk-880d496\" data-block-id=\"880d496\"><style>.stk-880d496 {margin-bottom:15px !important;}.stk-880d496 .stk-block-text__text{font-size:18px !important;color:var(--theme-palette-color-1, #145AE2) !important;font-weight:700 !important;}@media screen and (max-width: 1023px){.stk-880d496 .stk-block-text__text{font-size:18px !important;}}</style><p class=\"stk-block-text__text has-text-color has-palette-color-1-color has-text-align-center-tablet\">HOT OFFER</p></div>\n<!-- /wp:stackable/text -->\n\n<!-- wp:stackable/heading {\"uniqueId\":\"1c33bb0\",\"blockMargin\":{\"bottom\":25},\"fontSize\":40,\"useThemeTextMargins\":false,\"contentAlignTablet\":\"center\",\"blockMarginTablet\":{\"bottom\":25},\"fontSizeTablet\":30} -->\n<div class=\"wp-block-stackable-heading stk-block-heading stk-block-heading--v2 stk-block stk-1c33bb0\" id=\"libero-pulvinar-nonmassa-sedaccumsan-olerisque\" data-block-id=\"1c33bb0\"><style>.stk-1c33bb0 {margin-bottom:25px !important;}.stk-1c33bb0 .stk-block-heading__text{font-size:40px !important;}@media screen and (max-width: 1023px){.stk-1c33bb0 {margin-bottom:25px !important;}.stk-1c33bb0 .stk-block-heading__text{font-size:30px !important;}}</style><h2 class=\"stk-block-heading__text has-text-align-center-tablet\">Libero Pulvinar Nonmassa Sedaccumsan Olerisque</h2></div>\n<!-- /wp:stackable/heading -->\n\n<!-- wp:stackable/text {\"uniqueId\":\"05018d0\",\"blockMargin\":{\"top\":\"\",\"right\":\"\",\"bottom\":40,\"left\":\"\"},\"contentAlignTablet\":\"center\"} -->\n<div class=\"wp-block-stackable-text stk-block-text stk-block stk-05018d0\" data-block-id=\"05018d0\"><style>.stk-05018d0 {margin-bottom:40px !important;}</style><p class=\"stk-block-text__text has-text-align-center-tablet\">Integer at faucibus urna. Nullam condimentum leo id elit sagittis auctor. Curabitur elementum nunc a leo imperdiet, nec elementum diam elementum. </p></div>\n<!-- /wp:stackable/text -->\n\n<!-- wp:stackable/text {\"uniqueId\":\"e0c6329\",\"blockMargin\":{\"top\":\"\",\"right\":\"\",\"bottom\":40,\"left\":\"\"},\"contentAlignTablet\":\"center\"} -->\n<div class=\"wp-block-stackable-text stk-block-text stk-block stk-e0c6329\" data-block-id=\"e0c6329\"><style>.stk-e0c6329 {margin-bottom:40px !important;}</style><p class=\"stk-block-text__text has-text-align-center-tablet\">Phasellus risus turpis, pretium sit amet magna non, molestie ultricies enim. Nullam pulvinar felis at metus malesuada, nec convallis lacus commodo.</p></div>\n<!-- /wp:stackable/text -->\n\n<!-- wp:stackable/button-group {\"uniqueId\":\"6d510eb\",\"contentAlignTablet\":\"center\"} -->\n<div class=\"wp-block-stackable-button-group stk-block-button-group stk-block stk-6d510eb\" data-block-id=\"6d510eb\"><div class=\"stk-row stk-inner-blocks has-text-align-center-tablet stk-block-content stk-button-group\"><!-- wp:stackable/button {\"uniqueId\":\"6d13031\",\"buttonPadding\":{\"top\":16,\"right\":35,\"bottom\":16,\"left\":35},\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"fontSize\":\"15\"} -->\n<div class=\"wp-block-stackable-button stk-block-button stk-block stk-6d13031\" data-block-id=\"6d13031\"><style>.stk-6d13031 .stk-button{padding-top:16px !important;padding-right:35px !important;padding-bottom:16px !important;padding-left:35px !important;}.stk-6d13031 .stk-button__inner-text{font-size:15px !important;font-weight:700 !important;text-transform:uppercase !important;}@media screen and (max-width: 1023px){.stk-6d13031 .stk-button__inner-text{font-size:15px !important;}}</style><a class=\"stk-link stk-button stk--hover-effect-darken\" href=\"\"><span class=\"stk-button__inner-text\">Learn More</span></a></div>\n<!-- /wp:stackable/button --></div></div>\n<!-- /wp:stackable/button-group --></div></div></div>\n<!-- /wp:stackable/column --></div></div>\n<!-- /wp:stackable/columns -->','Home','','publish','closed','closed','','home','','','2026-04-24 15:41:39','2026-04-24 15:41:39','',0,'https://startersites.io/blocksy/car-service/?page_id=2',0,'page','',0),
(590,1,'2022-03-14 16:48:17','2022-03-14 16:48:17','<!-- wp:heading --><h2>Who we are</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Our website address is: https://startersites.io/blocksy/car-service.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Comments</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>When visitors leave comments on the site we collect the data shown in the comments form, and also the visitor&#8217;s IP address and browser user agent string to help spam detection.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>An anonymized string created from your email address (also called a hash) may be provided to the Gravatar service to see if you are using it. The Gravatar service privacy policy is available here: https://automattic.com/privacy/. After approval of your comment, your profile picture is visible to the public in the context of your comment.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Media</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you upload images to the website, you should avoid uploading images with embedded location data (EXIF GPS) included. Visitors to the website can download and extract any location data from images on the website.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Cookies</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment on our site you may opt-in to saving your name, email address and website in cookies. These are for your convenience so that you do not have to fill in your details again when you leave another comment. These cookies will last for one year.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>If you visit our login page, we will set a temporary cookie to determine if your browser accepts cookies. This cookie contains no personal data and is discarded when you close your browser.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>When you log in, we will also set up several cookies to save your login information and your screen display choices. Login cookies last for two days, and screen options cookies last for a year. If you select &quot;Remember Me&quot;, your login will persist for two weeks. If you log out of your account, the login cookies will be removed.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>If you edit or publish an article, an additional cookie will be saved in your browser. This cookie includes no personal data and simply indicates the post ID of the article you just edited. It expires after 1 day.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Embedded content from other websites</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Articles on this site may include embedded content (e.g. videos, images, articles, etc.). Embedded content from other websites behaves in the exact same way as if the visitor has visited the other website.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>These websites may collect data about you, use cookies, embed additional third-party tracking, and monitor your interaction with that embedded content, including tracking your interaction with the embedded content if you have an account and are logged in to that website.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Who we share your data with</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you request a password reset, your IP address will be included in the reset email.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>How long we retain your data</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment, the comment and its metadata are retained indefinitely. This is so we can recognize and approve any follow-up comments automatically instead of holding them in a moderation queue.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>For users that register on our website (if any), we also store the personal information they provide in their user profile. All users can see, edit, or delete their personal information at any time (except they cannot change their username). Website administrators can also see and edit that information.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>What rights you have over your data</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you have an account on this site, or have left comments, you can request to receive an exported file of the personal data we hold about you, including any data you have provided to us. You can also request that we erase any personal data we hold about you. This does not include any data we are obliged to keep for administrative, legal, or security purposes.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Where we send your data</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Visitor comments may be checked through an automated spam detection service.</p><!-- /wp:paragraph -->','Privacy Policy','','draft','closed','open','','privacy-policy','','','2022-03-14 16:48:17','2022-03-14 16:48:17','',0,'https://startersites.io/blocksy/car-service/?page_id=3',0,'page','',0),
